INSERT INTO "public"."assessment_results" ("id", "user_id", "phase_2_category", "personality", "goal_status", "confidence", "reasoning", "raw_answers", "selected_class", "phase3_result", "phase3_answers", "phase3_analysis", "final_answers", "stream_scores", "recommended_stream", "final_analysis", "stream_pros", "stream_cons", "simulation_career", "simulation_questions", "simulation_answers", "simulation_evaluation") VALUES
	(1, 1, 'Focused Specialist', 'Introvert', 'Goal Aware', 0.9, 'The user shows a strong preference for solitary learning, written communication, and independent problem-solving. Despite a slight preference for high-potential ''wildcards,'' their clear visualization of a straight career highway and desire to specialize strongly indicates a Focused Specialist profile.', '{"Q1_SocialBattery": "A quiet morning with a book/coffee.", "Q2_Communication": "Sending a carefully crafted email.", "Q3_Workspace": "A bustling co-working space with open desks.", "Q4_ProblemSolving": "Digging through Google/Manuals solo.", "Q5_MeetingRole": "The person taking detailed, silent notes.", "Q6_LearningStyle": "Watching a deep-dive documentary alone.", "Q7_GoalPath": "A straight highway with a clear destination.", "Q8_GoalVision": "I have a \"Lifestyle\" I want, but the job is tbd.", "Q9_GoalSpeed": "I want to specialize and be the best at one thing.", "Q10_GoalChoice": "I\u2019d pick the \"Wildcard\" path with high potential."}', '10th', 'Phase 3 Completed', '{"S1_TheBug": "A", "S2_TheWorkspace": "B", "S3_TheMastery": "A", "S4_TheDeadline": "B", "S5_TheReward": "A", "S6_TheTool": "B", "S7_TheResearch": "A", "S8_TheCommunication": "B", "S9_TheCriticism": "A", "S10_TheLongGame": "B"}', 'Your responses reveal that you are a quintessential **Focused Specialist** who thrives on technical precision, deep-dive research, and a highly structured workflow. By choosing to master a single tool and preferring incremental, steady progress over chaotic multitasking, you demonstrate a disciplined approach to learning that favors quality and internal mastery. To maximize this strength, you should schedule dedicated "deep work" blocks for your most complex subjects, allowing you to satisfy your need for exhaustive detail without the interruption of shifting tasks. While your specialized focus is a significant asset, remember to occasionally "zoom out" to ensure your deep-dives remain aligned with broader 