INSERT INTO "public"."career_paths" ("id", "user_id", "career_title", "path_data", "reminders", "created_at") VALUES
	(1, 13, 'Test Career', '{"steps": [{"step": 1, "action": "Foundations", "description": "Learn basics.", "completed": false, "courses": [{"name": "Python for Beginners", "url": "https://www.coursera.org/learn/python"}, "Old Course Name (String)"]}], "progress_percentage": 0}', 'null', '2026-03-07 20:01:38+00'),
	(2, 7, 'Business Analytics and Data Science', '{"steps": [{"step": 1, "action": "Launchpad to Analytics", "description": "At this stage, we focus on building foundational knowledge in mathematics, statistics, and computer science, which are essential for a career in Business Analytics and Data Science. As a Strategic Builder, you''ll enjoy understanding how different components of data analysis fit together. By laying a strong foundation, you''ll be able to tackle more complex challenges later on.", "skills": ["Basic Programming in Python", "Data Visualization with matplotlib", "Statistical Analysis"], "courses": ["Python for Everybody (Coursera)", "Data Visualization with Python (YouTube)"], "project": "Movie Ratings Analyzer", "timeline": "Months 1-3", "completed": true}, {"step": 2, "action": "Data Dive", "description": "Now, we dive deeper into data analysis, exploring databases, data structures, and machine learning fundamentals. Your ambivert personality will help you navigate both solo study and group discussions with ease. This step is crucial for developing your ability to work with various data types and tools.", "skills": ["Relational Databases with SQL", "Data Preprocessing with Pandas", "Introduction to Machine Learning with Scikit-learn"], "courses": ["Database Management Essentials (edX)", "Python Data Science Handbook (book)"], "project": "Personal Finance Tracker", "timeline": "Months 4-6", "completed": true}, {"step": 3, "action": "Analytics Accelerator", "description": "Here, we accelerate your analytics skills by introducing more advanced machine learning concepts, data modeling, and visualization techniques. Your Strategic Builder mindset will help you optimize processes and identify efficient paths to problem-solving. This phase is where you start applying your knowledge to real-world problems.", "skills": ["Supervised and Unsupervised Learning", "Time Series Analysis", "Tableau for Data Visualization"], "courses": ["Machine Learning Crash Course (Google)", "Tableau Training (Tableau website)"], "project": "Customer Segmentation for E-commerce", "timeline": "Months 7-9", "completed": true}, {"step": 4, "action": "Data Science Deep Dive", "description": "At this intermediate level, we delve into deeper data science concepts, including natural language processing, deep learning, and big data analytics. Your ability to balance theoretical knowledge with practical application will serve you well. Networking with professionals and participating in data science competitions will also become more important.", "skills": ["Natural Language Processing with NLTK", "Deep Learning with TensorFlow", "Apache Spark for Big Data"], "courses": ["Natural Language Processing (Stanford University on Coursera)", "Deep Learning Specialization (Coursera)"], "project": "Sentiment Analysis of Movie Reviews", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialization Station", "description": "Now, it''s time to specialize in areas like predictive analytics, business intelligence, or data engineering, enhancing your profile with specialized skills. Your Strategic Builder profile will help you choose the most impactful areas for specialization. This phase involves advanced projects and possibly contributing to open-source data science projects.", "skills": ["Predictive Modeling with Gradient Boosting", "Data Engineering with AWS", "Business Intelligence with Power BI"], "courses": ["Predictive Modeling (DataCamp)", "AWS Certified Data Engineer (AWS)"], "project": "Stock Market Predictor", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Professional Polish", "description": "In the final stretch, we focus on polishing your professional profile, including resume building, advanced portfolio development, and preparing for technical interviews. Your ambivert nature will help you balance self-promotion with humility. This step is about demonstrating your expertise and readiness to join the industry.", "skills": ["Resume Building for Data Science", "Advanced SQL for Data Analysis", "Data Storytelling"], "courses": ["Data Science Resume Building (Glassdoor)", "SQL for Data Analysis (DataCamp)"], "project": "Comprehensive Data Science Portfolio", "timeline": "Months 16-18", "completed": false}], "internships": ["Data Analyst at Accenture", "Business Intelligence Intern at IBM"], "career_outlook": {"salary_range": "\u20b98 lakhs - \u20b925 lakhs per annum (in India) or $60,000 - $120,000 per annum (in the US)", "top_companies": ["Google", "Microsoft", "Accenture"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete foundational courses", "reminder": "Review notes and practice regularly"}, {"milestone": "Start building a personal project portfolio", "reminder": "Dedicate at least 5 hours a week to project development"}, {"milestone": "Networking and joining data science communities", "reminder": "Attend webinars, meetups, and engage in online forums"}], "progress_percentage": 50}', '[{"milestone": "Complete foundational courses", "reminder": "Review notes and practice regularly"}, {"milestone": "Start building a personal project portfolio", "reminder": "Dedicate at least 5 hours a week to project development"}, {"milestone": "Networking and joining data science communities", "reminder": "Attend webinars, meetups, and engage in online forums"}]', '2026-03-07 20:03:11+00'),
	(3, 7, 'Architecture and Urban Systems', '{"steps": [{"step": 1, "action": "Building Foundations", "description": "As a Strategic Builder, you understand the importance of a solid base. We begin by setting up your foundational knowledge in architecture and urban systems. This step is crucial for understanding the basics of design, planning, and development. By mastering these fundamentals, you''ll be well-prepared to tackle more complex challenges ahead. Your ambivert personality will help you navigate both solo study sessions and group discussions effectively.", "skills": ["Introduction to Architecture", "Urban Planning Principles", "Basic Design Software"], "courses": [{"name": "Introduction to Architecture", "url": "https://www.coursera.org/specializations/architecture"}, {"name": "Urban Planning", "url": "https://www.udemy.com/course/urban-planning/"}], "project": "Design a Sustainable Community Center", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Exploring the Field", "description": "Now that we have the basics covered, it''s time to explore the field of architecture and urban systems more deeply. We''ll dive into the aspects of sustainability, technology, and social impact. This step will help you understand how your skills can be applied in real-world scenarios. Your Strategic Builder mindset will allow you to start seeing connections between different components of urban systems. As an ambivert, you''ll enjoy the mix of independent research and collaborative brainstorming sessions.", "skills": ["Sustainable Design", "Urban Technology", "Community Engagement"], "courses": [{"name": "Sustainable Architecture", "url": "https://www.edx.org/learn/sustainable-architecture"}, {"name": "Urban Informatics", "url": "https://www.youtube.com/playlist?list=PLQcdyQ5NuXUf5V7jRc8Z5Kl2M5XRR9L5"}], "project": "Propose a Green Roof Initiative for a Local Park", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Core Skill Development", "description": "In this step, we focus on building your core skills in architecture and urban systems. You''ll learn about advanced design tools, urban planning strategies, and how to analyze complex systems. Your Strategic Builder archetype will serve you well in understanding how these core skills fit into the larger picture of urban development. As you work on projects, your ambivert nature will allow you to balance focused work with feedback from peers and mentors.", "skills": ["Autodesk Revit", "Urban Planning Analysis", "System Dynamics"], "courses": [{"name": "Autodesk Revit Architecture", "url": "https://www.autodesk.com/products/revit/overview"}, {"name": "Urban Planning Analysis", "url": "https://www.esri.com/training/catalog/57875b48fc4c458a9f8054d6"}], "project": "Design an Efficient Public Transportation System for a Growing City", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Practical Application", "description": "It''s time to apply your skills to real-world problems. You''ll work on projects that challenge you to think critically about urban systems and design innovative solutions. This step is crucial for developing your portfolio and preparing for internships. Your Strategic Builder mindset will guide you in identifying efficient pathways to solve complex problems. As an ambivert, you''ll find value in both the solo effort of designing and the collaborative aspect of receiving and incorporating feedback.", "skills": ["Project Management", "Stakeholder Engagement", "Design Thinking"], "courses": [{"name": "Project Management for Designers", "url": "https://wwwSkillshare.com/classes/Project-Management-for-Designers/1420736169"}, {"name": "Design Thinking", "url": "https://www.coursera.org/specializations/design-thinking"}], "project": "Develop a Comprehensive Plan for a Riverfront Redevelopment Project", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialization and Portfolio Building", "description": "In this step, we focus on specializing in a particular area of architecture and urban systems that interests you the most. You''ll refine your skills, expand your professional network, and build a strong portfolio. Your Strategic Builder archetype will help you strategize how to present your skills and projects in the most compelling way. Your ambivert personality will be beneficial in navigating both the independent work of portfolio development and the social interactions of networking.", "skills": ["Specialized Design Software", "Advanced Urban Planning Strategies", "Portfolio Development"], "courses": [{"name": "Advanced Revit and BIM", "url": "https://www.udemy.com/course/advanced-revit-and-bim/"}, {"name": "Urban Planning Strategies", "url": "https://www.planning.org/pas/onlinecourses/"}], "project": "Create a Personal Portfolio Highlighting Urban Design and Planning Achievements", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Professional Readiness", "description": "In our final step, we prepare you for the professional world. You''ll refine your resume, practice interview skills, and apply for internships or jobs. Your Strategic Builder mindset will help you understand how your skills align with the needs of potential employers. As an ambivert, you''ll be comfortable with the balance between preparing for interviews and networking with professionals in your desired field.", "skills": ["Resume Writing", "Interview Preparation", "Professional Networking"], "courses": [{"name": "Resume and Cover Letter Writing", "url": "https://www.coursera.org/specializations/career-development"}, {"name": "Interview Preparation", "url": "https://www.linkedin.com/learning/interview-preparation"}], "project": "Secure an Internship with a Prestigious Architecture or Urban Planning Firm", "timeline": "Months 16-18", "completed": false}], "internships": ["Urban Planning Intern at AECOM", "Architecture Intern at Gensler"], "career_outlook": {"salary_range": "Entry-level: $50,000 - $70,000, Senior: $120,000 - $180,000", "top_companies": ["AECOM", "Gensler", "Skidmore, Owings & Merrill"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete foundational courses", "reminder": "Review and Practice consistently"}, {"milestone": "Start building your professional network", "reminder": "Attend industry events and join professional organizations"}, {"milestone": "Apply for internships", "reminder": "Tailor your resume and cover letter to each application"}]}', '[{"milestone": "Complete foundational courses", "reminder": "Review and Practice consistently"}, {"milestone": "Start building your professional network", "reminder": "Attend industry events and join professional organizations"}, {"milestone": "Apply for internships", "reminder": "Tailor your resume and cover letter to each application"}]', '2026-03-07 20:09:26+00'),
	(4, 7, 'Business Analytics and Data Science', '{"steps": [{"step": 1, "action": "Discover Your Foundation", "description": "We''re starting with the basics! Understanding the fundamentals of business analytics and data science is crucial for building a strong foundation. This step is essential for you as a Strategic Builder to establish a solid groundwork for your future skills. You''ll learn to appreciate how data can drive business decisions and how analytics can solve problems.", "skills": ["Data Analysis", "Statistical Reasoning", "Intro to Python"], "courses": [{"name": "Data Analysis with Python", "url": "https://www.coursera.org/learn/data-analysis-python"}, {"name": "Introduction to Data Science", "url": "https://www.youtube.com/results?search_query=introduction+to+data+science+for+beginners"}], "project": "School Performance Analysis", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Build Your Toolbox", "description": "Now that we have a foundation, it''s time to build your toolbox with essential skills like data visualization and machine learning. As a Strategic Builder, you know that having the right tools is crucial for efficient execution. You''ll learn to navigate data visualization tools and understand the basics of machine learning. This step will help you expand your skill set and prepare for more complex projects.", "skills": ["Data Visualization", "Machine Learning Basics", "SQL"], "courses": [{"name": "Data Visualization with Tableau", "url": "https://www.coursera.org/learn/data-visualization-tableau"}, {"name": "Machine Learning Crash Course", "url": "https://www.youtube.com/results?search_query=machine+learning+crash+course"}], "project": "Personal Expense Tracker", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Dive into Real Projects", "description": "With your foundation and toolbox in place, it''s time to dive into real projects that challenge you. As a Strategic Builder, you''re eager to apply your skills to practical problems. You''ll work on projects that involve data cleaning, feature engineering, and modeling. This step will help you develop a portfolio of work that demonstrates your capabilities.", "skills": ["Data Preprocessing", "Feature Engineering", "Model Evaluation"], "courses": [{"name": "Data Preprocessing with Python", "url": "https://www.datacamp.com/courses/data-preprocessing-with-python"}, {"name": "Feature Engineering for Machine Learning", "url": "https://www.youtube.com/results?search_query=feature+engineering+for+machine+learning"}], "project": "Predicting Stock Prices", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Network and Learn from Others", "description": "As you work on real projects, it''s essential to network with professionals and learn from their experiences. As a Strategic Builder, you know that collaboration and knowledge-sharing are vital for growth. You''ll attend webinars, join online communities, and participate in hackathons to expand your network and learn from others. This step will help you stay updated with industry trends and best practices.", "skills": ["Communication", "Collaboration", "Storytelling"], "courses": [{"name": "Effective Communication for Data Scientists", "url": "https://www.coursera.org/learn/effective-communication-data-scientists"}, {"name": "Data Science Storytelling", "url": "https://www.youtube.com/results?search_query=data+science+storytelling"}], "project": "Data Science Blogging", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Shine", "description": "Now that you have a strong foundation and a network of professionals, it''s time to specialize in a specific area of business analytics and data science. As a Strategic Builder, you''re eager to dive deep into a topic and become an expert. You''ll choose an area that interests you the most and work on advanced projects that demonstrate your expertise. This step will help you stand out in the job market and attract potential employers.", "skills": ["Advanced Machine Learning", "Deep Learning", "Natural Language Processing"], "courses": [{"name": "Advanced Machine Learning with Python", "url": "https://www.datacamp.com/courses/advanced-machine-learning-with-python"}, {"name": "Deep Learning with TensorFlow", "url": "https://www.youtube.com/results?search_query=deep+learning+with+tensorflow"}], "project": "Chatbot Development", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "With your specialization and advanced projects, you''re now ready to launch your career in business analytics and data science. As a Strategic Builder, you''re confident in your abilities and eager to make an impact. You''ll create a professional portfolio, prepare for common interview questions, and start applying for jobs that match your skills and interests. This step will help you transition into a successful career and continue to grow and learn.", "skills": ["Portfolio Creation", "Interview Preparation", "Job Search Strategies"], "courses": [{"name": "Data Science Portfolio Creation", "url": "https://www.coursera.org/learn/data-science-portfolio-creation"}, {"name": "Data Science Interview Preparation", "url": "https://www.youtube.com/results?search_query=data+science+interview+preparation"}], "project": "Personal Branding Website", "timeline": "Months 16-18", "completed": false}], "internships": ["Data Analyst at McKinsey", "Business Intelligence Developer at IBM"], "career_outlook": {"salary_range": "INR 6-20 lakhs per annum (entry-level to senior roles)", "top_companies": ["Google", "Amazon", "Microsoft"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete foundation courses", "reminder": "Months 1-3"}, {"milestone": "Start working on real projects", "reminder": "Months 7-9"}, {"milestone": "Specialize in a specific area", "reminder": "Months 13-15"}]}', '[{"milestone": "Complete foundation courses", "reminder": "Months 1-3"}, {"milestone": "Start working on real projects", "reminder": "Months 7-9"}, {"milestone": "Specialize in a specific area", "reminder": "Months 13-15"}]', '2026-03-07 20:13:24+00'),
	(5, 7, 'Architecture and Urban Systems', '{"steps": [{"step": 1, "action": "Build Foundations", "description": "We start by laying the groundwork for your future in Architecture and Urban Systems. This involves understanding the basics of design, urban planning, and the role of technology in shaping cities. By focusing on these essential elements, you''ll create a solid base for your future learning and projects.", "skills": ["Basic Design Principles", "Introduction to Urban Planning", "Familiarity with CAD Software"], "courses": [{"name": "Introduction to Architecture", "url": "https://www.coursera.org/specializations/architecture"}, {"name": "Urban Planning 101", "url": "https://www.youtube.com/results?search_query=urban+planning+101"}], "project": "Design a Sustainable Neighborhood", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore Creativity", "description": "Now, we dive deeper into the creative aspects of Architecture and Urban Systems. This step is about exploring different design software, understanding the principles of sustainable urban development, and learning from case studies. By doing so, you''ll develop a keen eye for detail and an ability to think creatively about complex urban challenges.", "skills": ["Proficiency in SketchUp", "Knowledge of Sustainable Urban Development", "Understanding of Urban Case Studies"], "courses": [{"name": "SketchUp for Architecture", "url": "https://www.udemy.com/course/sketchup-for-architecture/"}, {"name": "Sustainable Urban Development", "url": "https://www.youtube.com/results?search_query=sustainable+urban+development+tutorial"}], "project": "Create a Virtual City Model", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Develop Core Skills", "description": "At this stage, we focus on building core skills that are essential for a career in Architecture and Urban Systems. This includes learning advanced design software, understanding the principles of urban systems, and developing project management skills. By acquiring these skills, you''ll be well-equipped to handle complex projects and collaborate effectively with multidisciplinary teams.", "skills": ["Proficiency in Revit", "Understanding of Urban Systems", "Project Management Skills"], "courses": [{"name": "Autodesk Revit Architecture", "url": "https://www.autodesk.com/education/courses/revit-architecture"}, {"name": "Urban Systems and Infrastructure", "url": "https://www.coursera.org/specializations/urban-systems"}], "project": "Design a Green Building", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Network and Collaborate", "description": "We now emphasize the importance of networking and collaboration in the field of Architecture and Urban Systems. This step involves participating in design competitions, joining professional networks, and engaging in group projects. By doing so, you''ll build a strong professional network, learn from peers, and develop essential teamwork skills.", "skills": ["Participation in Design Competitions", "Professional Networking", "Collaboration and Teamwork"], "courses": [{"name": "Design Thinking", "url": "https://www.coursera.org/specializations/design-thinking"}, {"name": "Collaborative Design", "url": "https://www.youtube.com/results?search_query=collaborative+design+tutorial"}], "project": "Participate in a Design Competition", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Refine", "description": "At this advanced stage, we focus on specialization and refining your skills in Architecture and Urban Systems. This involves delving into specific areas of interest, such as sustainable urban planning or digital architecture, and developing a unique value proposition. By specializing, you''ll differentiate yourself in the job market and enhance your career prospects.", "skills": ["Specialization in Sustainable Urban Planning", "Digital Architecture", "Data Analysis for Urban Systems"], "courses": [{"name": "Sustainable Urban Planning", "url": "https://www.udemy.com/course/sustainable-urban-planning/"}, {"name": "Digital Architecture", "url": "https://www.youtube.com/results?search_query=digital+architecture+tutorial"}], "project": "Create a Smart City Proposal", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "In the final step, we prepare you for the professional world of Architecture and Urban Systems. This involves polishing your portfolio, practicing for interviews, and applying for jobs or internships. By launching your career with a strong foundation, you''ll be well on your way to achieving success in this exciting and rewarding field.", "skills": ["Portfolio Development", "Interview Preparation", "Job Application Strategies"], "courses": [{"name": "Portfolio Development for Architects", "url": "https://www.coursera.org/specializations/portfolio-development"}, {"name": "Interview Preparation for Architecture Jobs", "url": "https://www.youtube.com/results?search_query=interview+preparation+for+architecture+jobs"}], "project": "Finalize Your Professional Portfolio", "timeline": "Months 16-18", "completed": false}], "internships": ["Urban Planning Intern at AECOM", "Architecture Intern at Gensler"], "career_outlook": {"salary_range": "Entry-level: $50,000 - $70,000; Senior: $120,000 - $150,000", "top_companies": ["AECOM", "Gensler", "Skidmore, Owings & Merrill"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete Step 1-2 within the first 6 months", "reminder": "Stay focused on building a strong foundation in design principles and urban planning"}, {"milestone": "Network and collaborate with professionals in the field", "reminder": "Attend design events and join professional networks to build connections"}, {"milestone": "Specialize in a specific area of interest", "reminder": "Choose an area that aligns with your passions and career goals"}]}', '[{"milestone": "Complete Step 1-2 within the first 6 months", "reminder": "Stay focused on building a strong foundation in design principles and urban planning"}, {"milestone": "Network and collaborate with professionals in the field", "reminder": "Attend design events and join professional networks to build connections"}, {"milestone": "Specialize in a specific area of interest", "reminder": "Choose an area that aligns with your passions and career goals"}]', '2026-03-07 20:23:45+00'),
	(6, 14, 'Tech Entrepreneur', '{"steps": [{"step": 1, "action": "Ignite Your Spark", "description": "As a Focused Specialist, you''re naturally inclined towards mastering specific skills. At this stage, we focus on building a strong foundation in programming and understanding the basics of entrepreneurship. This step is crucial as it lays the groundwork for future learning and exploration. By igniting your spark, you''ll begin to understand what drives your passion for tech and entrepreneurship, and how you can turn that into a career.", "skills": ["Python Programming", "HTML/CSS", "Basic Entrepreneurship Concepts"], "courses": [{"name": "Python for Everybody", "url": "https://www.coursera.org/specializations/python"}, {"name": "HTML, CSS, and JavaScript for Web Developers", "url": "https://www.coursera.org/specializations/web-development"}], "project": "Personal Website Builder", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore Your Interests", "description": "Now that you''ve ignited your spark, it''s time to explore your interests in tech and entrepreneurship. This step is all about discovering what aspects of tech and entrepreneurship excite you the most. By exploring different areas, you''ll start to develop a deeper understanding of what you want to achieve as a Tech Entrepreneur. This exploration phase will help you narrow down your focus and prepare you for more advanced learning.", "skills": ["Data Structures", "Algorithms", "Web Development Frameworks"], "courses": [{"name": "Data Structures Specialization", "url": "https://www.coursera.org/specializations/data-structures"}, {"name": "Full Stack Web Development", "url": "https://www.youtube.com/results?search_query=full+stack+web+development+tutorial"}], "project": "To-Do List App", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Build Your Skills", "description": "As an Ambivert, you thrive in environments that balance solitude and social interaction. At this stage, we focus on building core skills that will help you succeed as a Tech Entrepreneur. This step is essential as it enables you to start working on real projects and collaborating with others. By building your skills, you''ll become more confident in your abilities and start to develop a professional network.", "skills": ["Machine Learning", "Database Management", "API Design"], "courses": [{"name": "Machine Learning Specialization", "url": "https://www.coursera.org/specializations/machine-learning"}, {"name": "Database Management Systems", "url": "https://www.youtube.com/results?search_query=database+management+systems+tutorial"}], "project": "Chatbot Development", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Launch Your Projects", "description": "With your skills in place, it''s time to launch your projects and start gaining real-world experience. This step is critical as it allows you to apply your knowledge, receive feedback, and iterate on your ideas. By launching your projects, you''ll start to build a portfolio that showcases your abilities as a Tech Entrepreneur. This portfolio will be essential when applying for jobs, internships, or pitching your ideas to investors.", "skills": ["Cloud Computing", "DevOps", "Cybersecurity"], "courses": [{"name": "Cloud Computing Specialization", "url": "https://www.coursera.org/specializations/cloud-computing"}, {"name": "DevOps Fundamentals", "url": "https://www.youtube.com/results?search_query=devops+fundamentals+tutorial"}], "project": "Personal Finance Manager", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "As you approach the final stages of your journey, it''s time to specialize in a specific area of tech entrepreneurship and polish your skills. This step is vital as it enables you to stand out in a competitive job market and demonstrate your expertise to potential employers or investors. By specializing and polishing your skills, you''ll become a highly sought-after candidate and increase your chances of success as a Tech Entrepreneur.", "skills": ["Artificial Intelligence", "Data Science", "Blockchain Development"], "courses": [{"name": "Artificial Intelligence Specialization", "url": "https://www.coursera.org/specializations/artificial-intelligence"}, {"name": "Blockchain Development", "url": "https://www.youtube.com/results?search_query=blockchain+development+tutorial"}], "project": "AI-Powered Virtual Assistant", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "With your skills specialized and polished, it''s time to launch your career as a Tech Entrepreneur. This final step is all about applying for jobs, internships, or pitching your ideas to investors. By launching your career, you''ll start to make a meaningful impact in the tech industry and achieve your goals as a Tech Entrepreneur.", "skills": ["Leadership", "Communication", "Strategic Thinking"], "courses": [{"name": "Leadership Specialization", "url": "https://www.coursera.org/specializations/leadership"}, {"name": "Strategic Thinking", "url": "https://www.youtube.com/results?search_query=strategic+thinking+tutorial"}], "project": "Startup Ideation and Pitching", "timeline": "Months 16-18", "completed": false}], "internships": ["Software Engineer Intern at Google", "Product Manager Intern at Microsoft"], "career_outlook": {"salary_range": "INR 8-20 lakhs per annum (entry-level to senior roles)", "top_companies": ["Google", "Amazon", "Microsoft"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete Phase 1-2 within 6 months", "reminder": "Stay focused and motivated to build a strong foundation"}, {"milestone": "Network with professionals in the tech industry", "reminder": "Attend conferences, join online communities, and connect with peers to build relationships and learn from their experiences"}]}', '[{"milestone": "Complete Phase 1-2 within 6 months", "reminder": "Stay focused and motivated to build a strong foundation"}, {"milestone": "Network with professionals in the tech industry", "reminder": "Attend conferences, join online communities, and connect with peers to build relationships and learn from their experiences"}]', '2026-03-07 20:27:37+00'),
	(7, 14, 'Tech Entrepreneur', '{"steps": [{"step": 1, "action": "Spark the Basics", "description": "This step is crucial for you as it lays the groundwork for understanding the fundamentals of technology and entrepreneurship. By sparking the basics, you''ll begin to grasp the concepts that will propel your journey forward. You''ll start to see how different technologies and entrepreneurial principles intersect, setting the stage for more advanced exploration.", "skills": ["HTML/CSS", "JavaScript basics", "Introduction to UX/UI design"], "courses": [{"name": "HTML, CSS, and JavaScript for Web Developers", "url": "https://www.coursera.org/specializations/html-css-javascript"}, {"name": "The Web Developer Bootcamp", "url": "https://www.udemy.com/course/the-web-developer-bootcamp/"}], "project": "Personal Website Builder", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore the Ecosystem", "description": "Now that you have a solid foundation, it''s time to explore the ecosystem of tech and entrepreneurship. This involves learning about different technologies, trends, and how they fit into the larger picture of your future career as a tech entrepreneur. By doing so, you''ll become well-versed in the terminology and concepts that are essential for success in this field.", "skills": ["Understanding of Agile methodologies", "Introduction to data structures and algorithms", "Basic knowledge of cybersecurity principles"], "courses": [{"name": "Introduction to Data Structures and Algorithms", "url": "https://www.coursera.org/learn/data-structures"}, {"name": "Agile Development Specialization", "url": "https://www.coursera.org/specializations/agile-development"}], "project": "To-Do List App with User Authentication", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Develop Your Core", "description": "In this phase, we focus on developing your core skills as a tech entrepreneur. This means diving deeper into programming languages, understanding database management, and learning about different frameworks and technologies. You''ll start to work on more complex projects that integrate multiple skills, preparing you for real-world challenges.", "skills": ["Proficiency in a programming language (e.g., Python)", "Understanding of database systems (e.g., MySQL)", "Knowledge of a frontend framework (e.g., React)"], "courses": [{"name": "Python for Everybody", "url": "https://www.coursera.org/specializations/python"}, {"name": "React: The Basics", "url": "https://www.udemy.com/course/react-the-basics/"}], "project": "E-commerce Website with Cart Functionality", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Build and Network", "description": "It''s time to put your skills into practice by building significant projects and networking within the tech community. This step is about applying what you''ve learned, getting feedback, and refining your skills further. Networking will help you learn about new opportunities, trends, and best practices in the industry.", "skills": ["Project management skills", "Understanding of cloud platforms (e.g., AWS)", "Experience with version control systems (e.g., Git)"], "courses": [{"name": "Introduction to Cloud Computing", "url": "https://www.coursera.org/specializations/cloud-computing"}, {"name": "Git & GitHub Tutorial for Beginners", "url": "https://www.youtube.com/watch?v=3RjQznt-8fo"}], "project": "Personal Project Showcase with Git", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "At this stage, you''ll specialize in a particular area of tech entrepreneurship that interests you the most. This could be anything from AI and machine learning to cybersecurity or data science. You''ll also focus on polishing your portfolio to showcase your expertise and accomplishments.", "skills": ["Advanced knowledge in a specialized area (e.g., machine learning)", "Understanding of entrepreneurship principles", "Experience with pitching ideas"], "courses": [{"name": "Machine Learning by Andrew Ng", "url": "https://www.coursera.org/specializations/machine-learning"}, {"name": "How to Start a Startup", "url": "https://www.youtube.com/watch?v=BL7A7Q4cull"}], "project": "AI-powered Chatbot for Customer Service", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch and Thrive", "description": "This final step is about preparing for the launch of your career as a tech entrepreneur. You''ll refine your professional online presence, practice interviewing skills, and prepare to apply for jobs or launch your own startup. This is the culmination of all your hard work and learning.", "skills": ["Finalize your professional portfolio", "Prepare for common interview questions", "Understand the process of launching a startup"], "courses": [{"name": "Startup Success: How to Launch a Successful Startup", "url": "https://www.udemy.com/course/startup-success/"}, {"name": "Crash Course on Interviewing for Tech Jobs", "url": "https://www.youtube.com/watch?v=d9VJx8XcQ7M"}], "project": "Develop a Minimum Viable Product (MVP) for Your Startup Idea", "timeline": "Months 16-18", "completed": false}], "internships": ["Software Engineer Intern at Google", "Product Development Intern at Microsoft"], "career_outlook": {"salary_range": "$80,000 - $200,000 per year", "top_companies": ["Google", "Microsoft", "Amazon"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete Phase 1-2 within the first 6 months", "reminder": "Stay focused on building a strong foundation"}, {"milestone": "Network actively during Phase 3-4", "reminder": "Attend industry events and join online communities"}, {"milestone": "Prepare for the job market or launching your startup by the end of Phase 6", "reminder": "Ensure your portfolio and professional online presence are updated and showcase your best work"}]}', '[{"milestone": "Complete Phase 1-2 within the first 6 months", "reminder": "Stay focused on building a strong foundation"}, {"milestone": "Network actively during Phase 3-4", "reminder": "Attend industry events and join online communities"}, {"milestone": "Prepare for the job market or launching your startup by the end of Phase 6", "reminder": "Ensure your portfolio and professional online presence are updated and showcase your best work"}]', '2026-03-07 20:32:42+00'),
	(8, 14, 'Research and Development Specialist', '{"steps": [{"step": 1, "action": "Launchpad to Basics", "description": "We begin by laying the foundation with fundamental concepts in research and development. This step matters because understanding the basics allows you to build a strong mindset for approaching complex problems. By focusing on the basics, you''ll set yourself up for success in more advanced topics and develop a solid work ethic.", "skills": ["Research Methodologies", "Data Analysis", "Scientific Writing"], "courses": [{"name": "Introduction to Research for Social Sciences and Humanities", "url": "https://www.coursera.org/specializations/research"}, {"name": "Data Analysis with Python", "url": "https://www.datacamp.com/courses/data-analysis-with-python"}], "project": "Science Journal Reviewer", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Engage", "description": "Now, we dive into exploring various fields related to research and development, understanding where your interests lie. This exploratory phase is crucial for identifying potential areas of specialization and starting to build your professional network. By engaging with different disciplines, you''ll broaden your perspective and develop a more nuanced understanding of the research landscape.", "skills": ["Literature Review", "Experimental Design", "Collaboration Tools"], "courses": [{"name": "The Craft of Research", "url": "https://www.youtube.com/watch?v=3Y-1t5xBaRc"}, {"name": "Introduction to Experimental Design", "url": "https://www.udemy.com/course/experimental-design/"}], "project": "Interdisciplinary Research Showcase", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Core Competency Builder", "description": "In this phase, we concentrate on building core competencies essential for a research and development specialist. This step is vital because mastering these skills will enable you to tackle complex projects and contribute meaningfully to research teams. By focusing on core competencies, you''ll develop a strong foundation for advanced research and innovation.", "skills": ["Statistical Modeling", "Machine Learning", "Programming in Python or R"], "courses": [{"name": "Python for Data Science", "url": "https://www.datacamp.com/courses/python-data-science"}, {"name": "Machine Learning with R", "url": "https://www.coursera.org/learn/machine-learning-with-r"}], "project": "Predictive Modeling Challenge", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Project Pioneer", "description": "Here, we shift focus towards applying your skills to real-world projects, enhancing your problem-solving abilities and learning to navigate project challenges. This step matters because it allows you to integrate theoretical knowledge with practical application, preparing you for the realities of working in research and development. By pioneering your own projects, you''ll develop invaluable experience and build a portfolio of work.", "skills": ["Project Management", "Team Leadership", "Innovation Strategies"], "courses": [{"name": "Project Management Fundamentals", "url": "https://www.edx.org/learn/project-management"}, {"name": "Leading Innovation", "url": "https://www.coursera.org/specializations/leading-innovation"}], "project": "Sustainable Technology Development", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialization Sprint", "description": "At this stage, we narrow down your focus to specialize in a specific area within research and development, honing your expertise and preparing you for advanced roles. This step is critical because specialization allows you to distinguish yourself in the field, opening up opportunities for leadership and high-impact research. By sprinting towards specialization, you''ll rapidly accelerate your career trajectory.", "skills": ["Advanced Data Analytics", "Artificial Intelligence", "Policy Development"], "courses": [{"name": "Advanced Data Science with IBM", "url": "https://www.coursera.org/professional-certificates/advanced-data-science"}, {"name": "AI for Everyone", "url": "https://www.deeplearning.ai/ai-for-everyone/"}], "project": "AI-Powered Research Tool", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Professional Launch", "description": "Finally, we prepare you for the professional world, focusing on polishing your portfolio, practicing interview skills, and securing high-level internships or job placements. This step matters because it marks the transition from learning to applying your skills in real-world settings, requiring you to be job-ready and networked. By launching your professional career, you''ll embark on a journey of continuous learning and growth.", "skills": ["Professional Networking", "Portfolio Development", "Interview Preparation"], "courses": [{"name": "Networking for Professionals", "url": "https://www.linkedin.com/learning/networking-for-professionals"}, {"name": "Resume and Interview Preparation", "url": "https://www.udemy.com/course/resume-and-interview-preparation/"}], "project": "Personal Branding and Career Portfolio", "timeline": "Months 16-18", "completed": false}], "internships": ["Research Intern at IBM", "Development Specialist Intern at Microsoft"], "career_outlook": {"salary_range": "Entry-level: $60,000 - $80,000, Senior: $120,000 - $150,000", "top_companies": ["Google", "Amazon", "NASA"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete foundational courses", "reminder": "Review notes regularly and practice problem-solving"}, {"milestone": "Start building a professional network", "reminder": "Attend industry events and join online forums"}, {"milestone": "Secure an internship", "reminder": "Tailor your resume and prepare for common interview questions"}]}', '[{"milestone": "Complete foundational courses", "reminder": "Review notes regularly and practice problem-solving"}, {"milestone": "Start building a professional network", "reminder": "Attend industry events and join online forums"}, {"milestone": "Secure an internship", "reminder": "Tailor your resume and prepare for common interview questions"}]', '2026-03-07 20:34:46+00'),
	(9, 7, 'Industrial Engineering and Operations Research', '{"steps": [{"step": 1, "action": "Lay the Foundation", "description": "We need to start by building a strong base in mathematics, particularly in areas like algebra, calculus, and statistics. You will learn how to analyze and solve problems using mathematical models. This will help you develop a logical and methodical approach to problem-solving, which is essential for industrial engineering and operations research. By mastering these foundational skills, you''ll be well-prepared for more advanced concepts in the field.", "skills": ["Linear Algebra", "Calculus", "Statistical Analysis"], "courses": [{"name": "Khan Academy Linear Algebra Course", "url": "https://www.khanacademy.org/math/linear-algebra"}, {"name": "MIT OpenCourseWare Calculus Course", "url": "https://ocw.mit.edu/courses/mathematics/18-01-calculus-i-fall-2007/"}], "project": "Mathematical Modeling of a Simple Production Line", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore the Field", "description": "Now that we have a solid foundation, it''s time to delve deeper into the world of industrial engineering and operations research. You''ll learn about the different tools and techniques used in the field, such as optimization methods, simulation, and data analysis. This will give you a broad understanding of the field and help you identify areas that interest you the most. By exploring these concepts, you''ll begin to see how they can be applied to real-world problems.", "skills": ["Optimization Techniques", "Simulation Modeling", "Data Analysis"], "courses": [{"name": "Coursera Optimization Course by University of Pennsylvania", "url": "https://www.coursera.org/learn/optimization"}, {"name": "Udemy Simulation Modeling Course", "url": "https://www.udemy.com/course/simulation-modeling/"}], "project": "Simulation of a Manufacturing System", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Develop Core Skills", "description": "It''s time to focus on developing the core skills required for industrial engineering and operations research. You''ll learn about programming languages like Python, R, or MATLAB, and how to apply them to solve complex problems. You''ll also learn about data visualization tools and techniques, which are essential for communicating insights and results to stakeholders. By mastering these skills, you''ll be able to tackle more complex projects and contribute to real-world solutions.", "skills": ["Python Programming", "Data Visualization", "Machine Learning"], "courses": [{"name": "Python for Data Science Course by DataCamp", "url": "https://www.datacamp.com/courses/python-data-science"}, {"name": "Tableau Data Visualization Course", "url": "https://www.tableau.com/learn/data-visualization"}], "project": "Development of a Predictive Maintenance Model", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Apply Skills to Real-World Projects", "description": "Now that we have developed the core skills, it''s time to apply them to real-world projects. You''ll work on projects that involve designing, optimizing, and analyzing systems, processes, and supply chains. This will help you develop a deeper understanding of the field and build a portfolio of projects that demonstrate your skills and abilities. By applying your skills to real-world problems, you''ll gain practical experience and become more confident in your abilities.", "skills": ["Supply Chain Management", "Process Improvement", "Quality Control"], "courses": [{"name": "MIT OpenCourseWare Supply Chain Management Course", "url": "https://ocw.mit.edu/courses/sloan-school-of-management/15-763j-supply-chain-fundamentals-fall-2016/"}, {"name": "ASQ Quality Control Course", "url": "https://www.asq.org/training/quality-control"}], "project": "Design and Optimization of a Supply Chain Network", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Network", "description": "As we approach the professional level, it''s time to specialize in a specific area of industrial engineering and operations research. You''ll learn about advanced topics like analytics, artificial intelligence, and digital transformation. You''ll also network with professionals in the field, attend conferences, and join online communities to stay up-to-date with the latest trends and developments. By specializing and networking, you''ll establish yourself as an expert in your chosen area and expand your professional opportunities.", "skills": ["Artificial Intelligence", "Digital Transformation", "Business Analytics"], "courses": [{"name": "Coursera Artificial Intelligence Course by Stanford University", "url": "https://www.coursera.org/learn/machine-learning"}, {"name": "edX Digital Transformation Course by MIT", "url": "https://www.edx.org/course/digital-transformation"}], "project": "Development of an AI-Powered Predictive Maintenance System", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "It''s time to launch your career as an industrial engineer or operations research professional. You''ll refine your portfolio, develop a strong resume, and prepare for job interviews. You''ll also learn about the latest trends and best practices in the field, and how to stay current with continuing education and professional development. By launching your career, you''ll embark on a rewarding and challenging journey that will take you to new heights.", "skills": ["Career Development", "Professional Networking", "Continuing Education"], "courses": [{"name": "LinkedIn Learning Career Development Course", "url": "https://www.linkedin.com/learning/career-development"}, {"name": "Coursera Professional Networking Course by University of Virginia", "url": "https://www.coursera.org/learn/professional-networking"}], "project": "Creation of a Personal Website and Professional Portfolio", "timeline": "Months 16-18", "completed": false}], "internships": ["Operations Research Intern at Amazon", "Industrial Engineering Intern at Toyota"], "career_outlook": {"salary_range": "INR 6-12 lakhs per annum (entry-level) to INR 20-30 lakhs per annum (senior-level)", "top_companies": ["Amazon", "Toyota", "General Electric"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete foundation courses", "reminder": "Months 1-3"}, {"milestone": "Develop core skills", "reminder": "Months 7-9"}, {"milestone": "Apply skills to real-world projects", "reminder": "Months 10-12"}, {"milestone": "Specialize and network", "reminder": "Months 13-15"}, {"milestone": "Launch your career", "reminder": "Months 16-18"}]}', '[{"milestone": "Complete foundation courses", "reminder": "Months 1-3"}, {"milestone": "Develop core skills", "reminder": "Months 7-9"}, {"milestone": "Apply skills to real-world projects", "reminder": "Months 10-12"}, {"milestone": "Specialize and network", "reminder": "Months 13-15"}, {"milestone": "Launch your career", "reminder": "Months 16-18"}]', '2026-03-13 19:06:48+00'),
	(10, 15, 'Startup Founder', '{"steps": [{"step": 1, "action": "Spark the Passion", "description": "We begin by igniting the spark within you, focusing on the foundational aspects of entrepreneurship and startup culture. This step matters because it lays the groundwork for understanding the entrepreneurial mindset and the basics of startup creation. By diving into the world of startups, you''ll discover what drives innovation and how to cultivate a founder''s mentality.", "skills": ["Entrepreneurial Mindset", "Basic Business Acumen", "Team Collaboration"], "courses": [{"name": "How to Start a Startup", "url": "https://www.youtube.com/watch?v=CBYhVcO4WgI"}, {"name": "Entrepreneurship 101", "url": "https://www.coursera.org/learn/entrepreneurship-101"}], "project": "DreamBiz", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Build the Basics", "description": "Now that the passion is ignited, we focus on building foundational skills in business, technology, and design. This step is crucial because it provides you with the essential tools to communicate your ideas effectively and understand the technical aspects of startup creation. By mastering these basics, you''ll be able to develop a solid business plan and prototype your ideas.", "skills": ["Business Modeling", "Design Thinking", "Basic Coding"], "courses": [{"name": "Business Model Canvas", "url": "https://www.youtube.com/watch?v=ipCRyNcKxRA"}, {"name": "Introduction to Design Thinking", "url": "https://www.coursera.org/learn/design-thinking"}], "project": "BizPlan", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Fuel the Fire", "description": "With the basics in place, we fuel your passion by diving deeper into the core skills required for startup success. This step is vital because it helps you develop a deeper understanding of the startup ecosystem, including market analysis, financial planning, and team building. By acquiring these skills, you''ll be able to navigate the challenges of the startup world and make informed decisions.", "skills": ["Market Analysis", "Financial Planning", "Team Management"], "courses": [{"name": "Market Analysis for Startups", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}, {"name": "Financial Planning for Entrepreneurs", "url": "https://www.udemy.com/course/financial-planning-for-entrepreneurs/"}], "project": "MarketSpark", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Networking Nirvana", "description": "As you fuel your passion, it''s time to connect with like-minded individuals and industry experts. This step is essential because it helps you build a professional network, find mentors, and stay updated on industry trends. By attending networking events, joining startup communities, and engaging in online forums, you''ll be able to learn from others, share your ideas, and gain valuable feedback.", "skills": ["Networking", "Public Speaking", "Community Building"], "courses": [{"name": "The Art of Networking", "url": "https://www.youtube.com/watch?v=-_H4yF9G5Oc"}, {"name": "Public Speaking for Entrepreneurs", "url": "https://www.coursera.org/learn/public-speaking"}], "project": "Networth", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Polish the Portfolio", "description": "With a strong foundation and network in place, it''s time to showcase your skills and accomplishments. This step is critical because it helps you demonstrate your capabilities to potential investors, partners, and customers. By creating a solid portfolio, you''ll be able to highlight your achievements, share your story, and attract attention to your startup.", "skills": ["Portfolio Development", "Storytelling", "Pitching"], "courses": [{"name": "Building a Startup Portfolio", "url": "https://www.youtube.com/watch?v=Kq6zr6kP9I0"}, {"name": "The Art of Storytelling for Entrepreneurs", "url": "https://www.udemy.com/course/the-art-of-storytelling-for-entrepreneurs/"}], "project": "PortfolioPro", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch and Thrive", "description": "You''ve made it to the final step! Now it''s time to launch your startup and thrive in the market. This step is the culmination of all your hard work, and it''s essential to stay focused, adaptable, and committed to your vision. By continuously learning, iterating, and improving, you''ll be able to overcome challenges, achieve success, and make a lasting impact.", "skills": ["Launch Strategy", "Growth Hacking", "Leadership"], "courses": [{"name": "Launch Strategy for Startups", "url": "https://www.youtube.com/watch?v=ZyG0q7fv8tE"}, {"name": "Growth Hacking for Entrepreneurs", "url": "https://www.coursera.org/learn/growth-hacking"}], "project": "LaunchLab", "timeline": "Months 16-18", "completed": false}], "internships": ["Startup Accelerator Intern", "Innovation Lab Intern"], "career_outlook": {"salary_range": "INR 6-20 lakhs (entry-level) to INR 50-100 lakhs (senior-level)", "top_companies": ["Flipkart", "Paytm", "Ola"], "future_scope": "High Growth"}, "reminders": [{"milestone": "Complete Phase 1", "reminder": "Review and practice entrepreneurial mindset and business acumen"}, {"milestone": "Complete Phase 2", "reminder": "Develop a solid business plan and prototype your ideas"}, {"milestone": "Complete Phase 3", "reminder": "Network and build relationships with industry experts and peers"}, {"milestone": "Complete Phase 4", "reminder": "Polish your portfolio and prepare for launch"}, {"milestone": "Complete Phase 5", "reminder": "Launch and thrive in the market, stay focused and adaptable"}, {"milestone": "Complete Phase 6", "reminder": "Continuously learn, iterate, and improve to achieve long-term success"}]}', '[{"milestone": "Complete Phase 1", "reminder": "Review and practice entrepreneurial mindset and business acumen"}, {"milestone": "Complete Phase 2", "reminder": "Develop a solid business plan and prototype your ideas"}, {"milestone": "Complete Phase 3", "reminder": "Network and build relationships with industry experts and peers"}, {"milestone": "Complete Phase 4", "reminder": "Polish your portfolio and prepare for launch"}, {"milestone": "Complete Phase 5", "reminder": "Launch and thrive in the market, stay focused and adaptable"}, {"milestone": "Complete Phase 6", "reminder": "Continuously learn, iterate, and improve to achieve long-term success"}]', '2026-03-13 19:19:42+00'),
	(11, 7, 'Industrial Engineering and Operations Research', '{"steps": [{"step": 1, "action": "Lay the Foundations", "description": "As a Strategic Builder, we need to start with the basics of Industrial Engineering and Operations Research, understanding the principles that guide these fields. This step is crucial because it sets the stage for advanced learning and practical application. By mastering the fundamentals, you''ll develop a solid understanding of the concepts that underpin your future career.", "skills": ["Mathematical Modeling", "Data Analysis", "Problem-Solving"], "courses": [{"name": "Introduction to Operations Research", "url": "https://www.coursera.org/learn/operations-research"}, {"name": "Industrial Engineering Fundamentals", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}], "project": {"name": "Optimization Starter Kit", "description": "Create a simple optimization model using linear programming to solve a basic supply chain problem.", "tools": ["Python", "PuLP Library"], "parameters": ["Cost Minimization", "Resource Allocation"]}, "detailed_task": "Solve a classic transportation problem using linear programming techniques, and document your approach and solution.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Engage", "description": "Now that we have the basics covered, it''s time to explore the field in more depth, looking into case studies, research papers, and real-world applications. This step helps you understand the practical side of Industrial Engineering and Operations Research, seeing how theories are applied in industry. By engaging with the community, you''ll start building connections and networking.", "skills": ["Simulation Modeling", "Stochastic Processes", "Decision Analysis"], "courses": [{"name": "Simulation Modeling and Analysis", "url": "https://www.udemy.com/course/simulation-modeling-and-analysis/"}, {"name": "Stochastic Processes in Operations Research", "url": "https://ocw.mit.edu/courses/electrical-engineering-and-computer-science/6-436j-fundamentals-of-probability-436j-6-046j-spring-2011/"}], "project": {"name": "Simulation Insights", "description": "Develop a simulation model for a manufacturing system to analyze throughput and efficiency.", "tools": ["AnyLogic", "SimPy"], "parameters": ["System Capacity", "Lead Time Reduction"]}, "detailed_task": "Analyze a real-world case study of an operation research project, identifying the methods used and the impact on the organization.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Build Core Skills", "description": "In this phase, we focus on acquiring the core skills that are essential for a career in Industrial Engineering and Operations Research, such as advanced data analysis and machine learning techniques. This step is vital because it positions you for tackling complex problems and contributing to innovative solutions. By mastering these skills, you become a more competitive candidate in the job market.", "skills": ["Advanced Data Analysis", "Machine Learning", "Supply Chain Management"], "courses": [{"name": "Data Science Specialization", "url": "https://www.coursera.org/specializations/data-science"}, {"name": "Machine Learning Crash Course", "url": "https://developers.google.com/machine-learning/crash-course"}], "project": {"name": "Predictive Analytics Portfolio", "description": "Develop predictive models for demand forecasting in a retail context, using machine learning algorithms.", "tools": ["Python", "TensorFlow", "Scikit-Learn"], "parameters": ["Model Accuracy", "Forecast Horizon"]}, "detailed_task": "Implement a machine learning model to solve a classification problem related to quality control in manufacturing.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Apply and Network", "description": "Now that you have built a strong foundation and core skills, it''s time to apply them in real-world contexts through projects and internships. This step matters because it gives you hands-on experience, exposure to different industries, and opportunities to build a professional network. By applying your knowledge and skills, you demonstrate your value to potential employers.", "skills": ["Project Management", "Communication", "Collaboration"], "courses": [{"name": "Project Management Principles", "url": "https://www.edx.org/course/project-management-principles"}, {"name": "Effective Communication", "url": "https://www.coursera.org/learn/effective-communication"}], "project": {"name": "Operational Excellence Project", "description": "Lead or participate in a project aimed at improving operations in a specific industry, applying tools and techniques learned.", "tools": ["Lean Six Sigma Tools", "Project Management Software"], "parameters": ["Process Efficiency", "Cost Savings"]}, "detailed_task": "Prepare a professional portfolio showcasing your projects, skills, and achievements to share with potential employers.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "At this level, we focus on specialization within Industrial Engineering and Operations Research, diving deeper into areas like advanced analytics, digital transformation, or sustainability. This step is crucial for becoming an expert in your chosen area, making you more attractive to top employers. By polishing your portfolio and networking, you position yourself for senior roles.", "skills": ["Advanced Analytics", "Digital Transformation", "Sustainability"], "courses": [{"name": "Advanced Analytics Certification", "url": "https://www.datacamp.com/tracks/advanced-analytics"}, {"name": "Digital Transformation in Operations", "url": "https://www.youtube.com/watch?v=XDf2nhfxSxI"}], "project": {"name": "Digital Transformation Roadmap", "description": "Develop a strategic roadmap for digitizing operations in a specific industry, incorporating advanced analytics and sustainability principles.", "tools": ["Tableau", "Power BI"], "parameters": ["Digital Maturity", "Sustainability Impact"]}, "detailed_task": "Research and present on the latest trends and technologies in Industrial Engineering and Operations Research, focusing on their applications.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "In the final step, we prepare for the launch of your career, focusing on high-level internships, job applications, and continuous learning. This step is about applying everything you''ve learned, making a strong entry into the professional world, and setting the stage for long-term success. By now, you have the skills, network, and portfolio to make a significant impact.", "skills": ["Leadership", "Strategy", "Innovation"], "courses": [{"name": "Leadership and Strategy", "url": "https://www.coursera.org/learn/leadership-strategy"}, {"name": "Innovation and Entrepreneurship", "url": "https://www.edx.org/course/innovation-entrepreneurship"}], "project": {"name": "Career Launchpad", "description": "Create a comprehensive plan for your career launch, including job applications, networking strategies, and a continuous learning path.", "tools": ["LinkedIn", "Personal Website/Blog"], "parameters": ["Job Fit", "Professional Growth"]}, "detailed_task": "Finalize your professional portfolio, tailor your resume and cover letter, and prepare for common interview questions in Industrial Engineering and Operations Research.", "timeline": "Months 16-18", "completed": false}], "internships": ["Operations Research Analyst Intern at a consulting firm", "Industrial Engineering Intern at a leading manufacturing company"], "career_outlook": {"salary_range": "$60,000 - $120,000 per year", "top_companies": ["Deloitte", "IBM", "General Motors"], "hiring_trends": "There is a growing demand for professionals with expertise in Industrial Engineering and Operations Research, especially in areas like supply chain optimization, predictive analytics, and digital transformation. Recruiters look for candidates with a strong analytical background, problem-solving skills, and the ability to communicate complex ideas effectively. The field is rapidly evolving, with technologies like AI, IoT, and blockchain changing the landscape of operations and manufacturing.", "future_scope": "Industrial Engineering and Operations Research is a high-growth field with a wide range of applications across industries. As technology continues to advance and businesses seek more efficient and sustainable operations, the demand for skilled professionals in this area will only increase. This career path offers the opportunity to work on challenging projects, lead innovation, and make a significant impact on business and society, making it a safe bet for the next decade."}, "reminders": [{"milestone": "Complete the first course in the Data Science Specialization", "reminder": "Don''t forget to apply for internships during your senior year"}, {"milestone": "Finalize the Career Launchpad project", "reminder": "Update your LinkedIn profile and start networking with professionals in your desired field"}]}', '[{"milestone": "Complete the first course in the Data Science Specialization", "reminder": "Don''t forget to apply for internships during your senior year"}, {"milestone": "Finalize the Career Launchpad project", "reminder": "Update your LinkedIn profile and start networking with professionals in your desired field"}]', '2026-03-22 19:41:53+00'),
	(12, 17, 'Social Entrepreneur', '{"steps": [{"step": 1, "action": "Spark Your Passion", "description": "We''re starting with the basics to lay a strong foundation for your journey as a Social Entrepreneur. At this stage, you''ll learn about the fundamentals of social entrepreneurship, including understanding social problems, identifying opportunities, and developing a business mindset. This step matters because it sets the tone for your future growth and helps you understand the landscape of social entrepreneurship.", "skills": ["Understanding of social issues", "Basic business principles", "Community engagement"], "courses": [{"name": "Social Entrepreneurship 101", "url": "https://www.coursera.org/specializations/social-entrepreneurship"}, {"name": "How to Change the World", "url": "https://www.youtube.com/watch?v=2BwDtX-3QI8"}], "project": {"name": "Social Impact Project", "description": "Design a project that addresses a local social issue, considering community needs and potential solutions.", "tools": ["Canva", "Google Forms"], "parameters": ["Impact measurement", "Community engagement strategies"]}, "detailed_task": "Research and list 10 social issues in your local community, then choose one to focus on for your project.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Build Your Base", "description": "Now, we''re building on your foundation by introducing key concepts and skills necessary for social entrepreneurship. This step is crucial because it helps you develop a deeper understanding of the field and starts to shape your unique perspective as a social entrepreneur. You''ll learn about marketing, finance, and leadership, applying these skills to your project.", "skills": ["Marketing fundamentals", "Financial planning", "Leadership skills"], "courses": [{"name": "Marketing in a Digital World", "url": "https://www.coursera.org/specializations/marketing"}, {"name": "Financial Planning for Social Entrepreneurs", "url": "https://www.youtube.com/watch?v=K6xMTHYj5Qo"}], "project": {"name": "Marketing Strategy Plan", "description": "Create a marketing strategy for your social impact project, considering budget constraints and target audience.", "tools": ["Adobe Creative Cloud", "Google Analytics"], "parameters": ["Budget allocation", "Target audience engagement"]}, "detailed_task": "Develop a basic marketing plan for your project, including social media and community outreach strategies.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Dive Into Details", "description": "At this intermediate stage, you''re diving deeper into the specifics of social entrepreneurship, focusing on core skills and practical application. This step matters because it helps you transition from theory to practice, applying your knowledge to real-world problems. You''ll explore project management, partnership development, and innovation strategies.", "skills": ["Project management", "Partnership development", "Innovation strategies"], "courses": [{"name": "Project Management for Social Entrepreneurs", "url": "https://www.udemy.com/course/project-management-for-social-entrepreneurs/"}, {"name": "Innovating for Social Impact", "url": "https://www.youtube.com/watch?v=RjwL2NzHuqA"}], "project": {"name": "Partnership Development Plan", "description": "Identify and outreach to potential partners for your social impact project, developing a partnership strategy.", "tools": ["LinkedIn", "Partner relationship management software"], "parameters": ["Partner engagement", "Mutual benefit analysis"]}, "detailed_task": "Research and outreach to 5 potential partners for your project, drafting a partnership proposal.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Elevate Your Impact", "description": "You''re now at a stage where you can significantly elevate the impact of your project by refining your strategies and expanding your network. This step is critical because it prepares you for more complex challenges and opportunities, helping you scale your project and amplify its effects. You''ll delve into scaling strategies, fundraising, and community engagement.", "skills": ["Scaling strategies", "Fundraising techniques", "Advanced community engagement"], "courses": [{"name": "Scaling Social Impact", "url": "https://www.coursera.org/specializations/scaling-social-impact"}, {"name": "Fundraising Strategies for Social Entrepreneurs", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}], "project": {"name": "Scaling Plan", "description": "Develop a plan to scale your social impact project, considering expansion strategies and resource allocation.", "tools": ["Business Model Canvas", "Resource allocation software"], "parameters": ["Expansion strategy", "Resource allocation efficiency"]}, "detailed_task": "Draft a comprehensive scaling plan for your project, including financial projections and operational strategies.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Refine Your Craft", "description": "At this professional stage, you''re refining your skills and expertise, preparing for high-level opportunities. This step is essential because it helps you polish your portfolio, develop a personal brand, and positions you as a leader in social entrepreneurship. You''ll focus on advanced leadership, innovation, and strategic planning.", "skills": ["Advanced leadership", "Innovation methodologies", "Strategic planning"], "courses": [{"name": "Advanced Leadership for Social Entrepreneurs", "url": "https://www.udemy.com/course/advanced-leadership-for-social-entrepreneurs/"}, {"name": "Strategic Planning for Social Impact", "url": "https://www.youtube.com/watch?v=jNQXAC9IVRw"}], "project": {"name": "Personal Brand Development", "description": "Develop a personal brand as a social entrepreneur, including a professional portfolio and online presence.", "tools": ["WordPress", "Personal branding software"], "parameters": ["Unique value proposition", "Consistent branding"]}, "detailed_task": "Create a professional portfolio showcasing your projects and skills as a social entrepreneur.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Legacy", "description": "You''ve reached the final stage of your journey, where you launch your legacy as a social entrepreneur. This step matters because it''s where you apply everything you''ve learned, turning your vision into a tangible reality. You''ll focus on launching your project, securing funding, and establishing your organization.", "skills": ["Project launch strategies", "Funding acquisition", "Organizational setup"], "courses": [{"name": "Launching Your Social Venture", "url": "https://www.coursera.org/specializations/launching-your-social-venture"}, {"name": "Securing Funding for Social Impact", "url": "https://www.youtube.com/watch?v=KkGDhFp6H9M"}], "project": {"name": "Project Launch Plan", "description": "Finalize and launch your social impact project, incorporating all learned strategies and skills.", "tools": ["Project management software", "Launch planning toolkit"], "parameters": ["Launch strategy", "Post-launch evaluation"]}, "detailed_task": "Finalize your project plan, secure necessary funding, and launch your social impact project.", "timeline": "Months 16-18", "completed": false}], "internships": ["Social entrepreneurship internship at Ashoka", "Program development internship at the Bill and Melinda Gates Foundation"], "career_outlook": {"salary_range": "Entry-level: $40,000 - $60,000, Senior: $80,000 - $110,000", "top_companies": ["Acumen", "Skoll Foundation", "Echoing Green"], "hiring_trends": "There''s a growing demand for social entrepreneurs who can develop innovative solutions to pressing social issues. Recruiters look for candidates with a strong passion for social impact, alongside skills in business management, project development, and community engagement. The ability to scale projects, secure funding, and build strategic partnerships is highly valued.", "future_scope": "Social entrepreneurship is a high-growth field, with immense potential for making a positive impact on a global scale. As the world faces increasing social and environmental challenges, the demand for skilled social entrepreneurs will continue to rise, providing a stable and fulfilling career path for those who are passionate about creating change."}, "reminders": [{"milestone": "Complete project proposals", "reminder": "Send reminders to partners and team members about upcoming project proposal deadlines."}, {"milestone": "Apply for internships", "reminder": "Research and apply for at least 3 internships in social entrepreneurship by the end of the month."}]}', '[{"milestone": "Complete project proposals", "reminder": "Send reminders to partners and team members about upcoming project proposal deadlines."}, {"milestone": "Apply for internships", "reminder": "Research and apply for at least 3 internships in social entrepreneurship by the end of the month."}]', '2026-03-26 12:48:33.638673+00'),
	(14, 23, 'Research Scientist', '{"steps": [{"step": 1, "action": "Lay the Foundations", "description": "We start by building a strong foundation in the sciences, focusing on research methods, data analysis, and critical thinking. This step matters because it sets the stage for all future learning and exploration. By mastering these basics, you''ll develop a robust mindset that will serve you well in your future research endeavors.", "skills": ["Research Design", "Statistical Analysis", "Academic Writing"], "courses": [{"name": "Introduction to Research Methods", "url": "https://www.coursera.org/learn/research-methods"}, {"name": "Data Analysis with Python", "url": "https://www.youtube.com/watch?v=vmEodb1Iouch"}], "project": {"name": "Science Explorer", "description": "Design and conduct a simple experiment to test a hypothesis, collecting and analyzing data to draw conclusions.", "tools": ["Python with Pandas", "Excel"], "parameters": ["Sample Size", "Confounding Variables"]}, "detailed_task": "Read and summarize 5 recent research papers in your desired field, identifying key methodologies and takeaways.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Engage", "description": "Now, we explore various fields of science, discovering where your passions and strengths lie. This step is crucial because it allows you to experience different areas of research, helping you narrow down your focus. Through this exploration, you''ll begin to develop a sense of purpose and direction in your research journey.", "skills": ["Literature Review", "Experimental Design", "Collaboration"], "courses": [{"name": "Scientific Writing and Communication", "url": "https://www.udemy.com/course/scientific-writing-and-communication/"}, {"name": "Introduction to Research Ethics", "url": "https://www.youtube.com/watch?v=qYryKB8u6Gg"}], "project": {"name": "Research Sampler", "description": "Conduct a literature review on a topic of interest, identifying gaps and areas for future research.", "tools": ["Mendeley", "Zotero"], "parameters": ["Database Selection", "Inclusion/Exclusion Criteria"]}, "detailed_task": "Participate in online forums or discussion groups related to your field of interest, engaging in meaningful conversations and learning from others.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Build Core Skills", "description": "At this stage, we focus on developing the core skills required for a research scientist, including data analysis, programming, and problem-solving. This step is vital because it equips you with the technical abilities needed to excel in research. By mastering these skills, you''ll be able to tackle complex research questions and contribute meaningfully to your field.", "skills": ["Python Programming", "Data Visualization", "Machine Learning"], "courses": [{"name": "Python for Data Science", "url": "https://www.datacamp.com/tracks/python-data-science"}, {"name": "Introduction to Machine Learning", "url": "https://www.coursera.org/learn/machine-learning"}], "project": {"name": "Data Detective", "description": "Analyze a dataset to identify trends, patterns, and correlations, presenting your findings in a clear and visually appealing manner.", "tools": ["Jupyter Notebook", "Tableau"], "parameters": ["Data Preprocessing", "Model Evaluation Metrics"]}, "detailed_task": "Create a personal project that applies machine learning to a real-world problem, documenting your process and results.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Apply and Refine", "description": "Here, we apply the skills and knowledge you''ve acquired, working on real-world projects and refining your expertise. This step is important because it allows you to integrate your learning, develop practical experience, and receive feedback. By applying your skills in meaningful contexts, you''ll deepen your understanding and become more confident in your abilities.", "skills": ["Grant Writing", "Research Proposal Development", "Team Collaboration"], "courses": [{"name": "Grant Writing for Researchers", "url": "https://www.researchadmin.ucla.edu/grant-writing"}, {"name": "Introduction to Research Team Management", "url": "https://www.youtube.com/watch?v=JF7oFm5l5Vc"}], "project": {"name": "Research Proposal", "description": "Develop a research proposal, outlining a clear research question, methodology, and expected outcomes.", "tools": ["Microsoft Word", "Google Docs"], "parameters": ["Literature Review Quality", "Methodological Soundness"]}, "detailed_task": "Collaborate with peers or mentors on a research project, contributing to the design, implementation, and dissemination of the research.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "Now, we focus on specializing in a specific area of research, refining your skills and building a professional portfolio. This step is critical because it enables you to establish yourself as an expert in your field, demonstrating your value to potential employers. By specializing and polishing your skills, you''ll become a highly competitive candidate for research positions.", "skills": ["Advanced Statistical Modeling", "Research Software Development", "Science Communication"], "courses": [{"name": "Advanced Statistical Modeling", "url": "https://www.edx.org/course/advanced-statistical-modeling"}, {"name": "Research Software Development with Python", "url": "https://www.youtube.com/watch?v=QUT1VXj3Q7w"}], "project": {"name": "Research Showcase", "description": "Create a professional portfolio, highlighting your research experience, skills, and achievements.", "tools": ["GitHub", "Personal Website"], "parameters": ["Code Quality", "Publication Record"]}, "detailed_task": "Publish a research paper in a peer-reviewed journal, navigating the submission and review process.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "Finally, we prepare you for the job market, tailoring your application materials and practicing your interview skills. This step is essential because it ensures you''re competitive in the job market, able to effectively communicate your skills and experience to potential employers. By launching your career with confidence and preparation, you''ll set yourself up for success and make a strong impression in your field.", "skills": ["Job Search Strategies", "Interview Preparation", "Professional Networking"], "courses": [{"name": "Job Search Strategies for Researchers", "url": "https://www.career.ucla.edu/job-search-strategies"}, {"name": "Introduction to Professional Networking", "url": "https://www.youtube.com/watch?v=kE2B4yL8JXo"}], "project": {"name": "Career Launchpad", "description": "Develop a personalized career plan, outlining your goals, objectives, and strategies for success.", "tools": ["Excel", "Trello"], "parameters": ["Job Market Analysis", "Personal Branding"]}, "detailed_task": "Network with professionals in your field, attending conferences, seminars, or workshops to learn about new developments and opportunities.", "timeline": "Months 16-18", "completed": false}], "internships": ["Research Assistant", "Data Science Intern"], "career_outlook": {"salary_range": "Entry-level (INR 4-6 lakhs per annum) to Senior (INR 15-20 lakhs per annum)", "top_companies": ["Indian Institute of Technology", "National Institutes of Health", "Google"], "hiring_trends": "The demand for research scientists is on the rise, particularly in fields like artificial intelligence, biotechnology, and environmental science. Recruiters look for candidates with strong technical skills, research experience, and excellent communication abilities. To stand out, it''s essential to build a robust portfolio, network with professionals, and stay up-to-date with industry trends and developments.", "future_scope": "The career of a research scientist is a ''High Growth'' path, offering numerous opportunities for advancement, collaboration, and innovation. With the increasing emphasis on scientific research and technological advancements, this field is expected to continue growing, providing a secure and fulfilling career for those who pursue it."}, "reminders": [{"milestone": "Complete Step 1-2 within the first 6 months", "reminder": "Stay focused and motivated, building a strong foundation for future success"}, {"milestone": "Apply for internships after completing Step 3-4", "reminder": "Gain practical experience and make industry connections to enhance your career prospects"}, {"milestone": "Finalize your career plan and portfolio by the end of Step 6", "reminder": "Be prepared to launch your career, showcasing your skills and experience to potential employers"}]}', '[{"milestone": "Complete Step 1-2 within the first 6 months", "reminder": "Stay focused and motivated, building a strong foundation for future success"}, {"milestone": "Apply for internships after completing Step 3-4", "reminder": "Gain practical experience and make industry connections to enhance your career prospects"}, {"milestone": "Finalize your career plan and portfolio by the end of Step 6", "reminder": "Be prepared to launch your career, showcasing your skills and experience to potential employers"}]', '2026-03-29 18:19:41.092737+00'),
	(13, 7, 'Architecture and Urban Systems', '{"steps": [{"step": 1, "action": "Build Your Foundation", "description": "As a Strategic Builder, you''ll begin by understanding the fundamentals of architecture and urban planning. This step is crucial because it sets the stage for your future learning and exploration. By grasping the basics, you''ll have a solid foundation to build upon and make informed decisions about your career path.", "skills": ["Introduction to Architecture", "Urban Planning Principles", "Design Software Basics"], "courses": [{"name": "Introduction to Architecture", "url": "https://www.coursera.org/specializations/architecture"}, {"name": "Urban Planning: Basics and Beyond", "url": "https://www.udemy.com/course/urban-planning/"}], "project": {"name": "Dream City Design", "description": "Design a sustainable and futuristic city, considering factors like transportation, energy efficiency, and green spaces.", "tools": ["Autodesk AutoCAD", "SketchUp"], "parameters": ["Population density", "Environmental impact", "Innovative transportation systems"]}, "detailed_task": "Research and create a list of 10 influential architects and their notable works, analyzing their design styles and philosophies.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Discover", "description": "In this step, you''ll delve deeper into the world of architecture and urban systems, exploring various styles, materials, and technologies. This phase is essential for developing your critical thinking and problem-solving skills. By exploring different aspects of the field, you''ll gain a broader understanding of the complexities involved and start to identify areas that interest you the most.", "skills": ["Building Information Modeling (BIM)", "Sustainable Design", "Urban Systems Analysis"], "courses": [{"name": "Building Information Modeling (BIM) Specialization", "url": "https://www.coursera.org/specializations/bim"}, {"name": "Sustainable Design and Development", "url": "https://www.udemy.com/course/sustainable-design/"}], "project": {"name": "Net-Zero Energy Building", "description": "Design a net-zero energy building, incorporating renewable energy sources, energy-efficient systems, and sustainable materials.", "tools": ["Revit", "EnergyPlus"], "parameters": ["Energy efficiency", "Water conservation", "Waste reduction"]}, "detailed_task": "Create a portfolio showcasing your understanding of different architectural styles and urban planning principles.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Develop Core Skills", "description": "Now that you have a solid foundation, it''s time to develop your core skills in architecture and urban systems. This step is critical for building your expertise and confidence. By mastering these skills, you''ll be able to tackle complex projects and contribute to real-world solutions.", "skills": ["Architectural Design", "Urban Planning and Policy", "Project Management"], "courses": [{"name": "Architectural Design Specialization", "url": "https://www.coursera.org/specializations/architectural-design"}, {"name": "Urban Planning and Policy", "url": "https://www.udemy.com/course/urban-planning-policy/"}], "project": {"name": "Smart City Master Plan", "description": "Develop a comprehensive master plan for a smart city, incorporating innovative technologies, sustainable practices, and community engagement.", "tools": ["GIS mapping", "Transportation planning software"], "parameters": ["Population growth", "Economic development", "Environmental sustainability"]}, "detailed_task": "Participate in online forums and discussions related to architecture and urban planning, sharing your thoughts and learning from others.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Apply and Refine", "description": "In this step, you''ll apply your skills and knowledge to real-world projects and scenarios, refining your expertise and learning from feedback. This phase is vital for developing your problem-solving skills and adaptability. By applying your knowledge in practical contexts, you''ll gain a deeper understanding of the complexities involved and develop a portfolio of projects that demonstrate your capabilities.", "skills": ["Construction Management", "Urban Systems Modeling", "Policy Analysis"], "courses": [{"name": "Construction Management Specialization", "url": "https://www.coursera.org/specializations/construction-management"}, {"name": "Urban Systems Modeling", "url": "https://www.udemy.com/course/urban-systems-modeling/"}], "project": {"name": "Resilient Water Management System", "description": "Design a resilient water management system for a urban area, considering factors like climate change, population growth, and water scarcity.", "tools": ["Water modeling software", "Geographic information systems (GIS)"], "parameters": ["Water supply", "Wastewater treatment", "Flood risk management"]}, "detailed_task": "Collaborate with peers or professionals on a project, applying your skills and knowledge to contribute to a shared goal.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "As you near the end of your journey, it''s time to specialize in a specific area of architecture and urban systems, polishing your skills and expertise. This step is essential for establishing yourself as a professional and standing out in a competitive job market. By specializing in a particular area, you''ll develop a deep understanding of the subject matter and be able to contribute meaningfully to projects and discussions.", "skills": ["Green Building Certification", "Urban Planning and Policy Analysis", "Advanced Design Software"], "courses": [{"name": "Green Building Certification", "url": "https://www.usgbc.org/education"}, {"name": "Urban Planning and Policy Analysis", "url": "https://www.udemy.com/course/urban-planning-policy-analysis/"}], "project": {"name": "Sustainable Urban Development Plan", "description": "Develop a comprehensive plan for sustainable urban development, incorporating green building practices, renewable energy sources, and innovative transportation systems.", "tools": ["LEED certification software", "Urban planning software"], "parameters": ["Energy efficiency", "Water conservation", "Waste reduction"]}, "detailed_task": "Create a professional portfolio and online presence, showcasing your skills, experience, and achievements.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "You''ve reached the final step, where you''ll launch your career in architecture and urban systems. This phase is exciting and challenging, as you''ll be applying your skills and knowledge in real-world contexts. By following the steps outlined in this roadmap, you''ll be well-prepared to succeed in your chosen career and make a meaningful contribution to the field.", "skills": ["Professional Communication", "Project Management", "Leadership and Teamwork"], "courses": [{"name": "Professional Communication in Architecture", "url": "https://www.coursera.org/specializations/professional-communication"}, {"name": "Project Management for Architects", "url": "https://www.udemy.com/course/project-management-architects/"}], "project": {"name": "Capstone Project: Urban Regeneration", "description": "Develop a comprehensive plan for urban regeneration, incorporating sustainable design, community engagement, and economic development strategies.", "tools": ["Autodesk Revit", "Urban planning software"], "parameters": ["Community participation", "Economic viability", "Environmental sustainability"]}, "detailed_task": "Network with professionals in the field, attending conferences, workshops, and job fairs to establish connections and learn about new opportunities.", "timeline": "Months 16-18", "completed": false}], "internships": ["Urban Planning Intern at a government agency", "Sustainable Design Intern at a architecture firm"], "career_outlook": {"salary_range": "INR 4-12 lakhs per annum (entry-level) to INR 20-50 lakhs per annum (senior-level)", "top_companies": ["AECOM", "Arup", "Gensler"], "hiring_trends": "The demand for skilled professionals in architecture and urban systems is on the rise, with a focus on sustainable design, urban planning, and project management. Recruiters look for candidates with strong technical skills, creativity, and problem-solving abilities, as well as excellent communication and teamwork skills. The industry is shifting towards more integrated and interdisciplinary approaches, with a emphasis on collaboration and innovation.", "future_scope": "Architecture and urban systems is a high-growth field, with a wide range of career opportunities and specializations. As the world''s population continues to urbanize, the need for sustainable, resilient, and livable cities will drive demand for skilled professionals in this field. With the right skills and knowledge, you can make a meaningful contribution to shaping the future of our cities and communities."}, "reminders": [{"milestone": "Complete Step 1-2", "reminder": "Review the fundamentals of architecture and urban planning, and explore different styles and materials."}, {"milestone": "Complete Step 3-4", "reminder": "Develop your core skills in architectural design, urban planning, and project management, and apply them to real-world projects."}, {"milestone": "Complete Step 5-6", "reminder": "Specialize in a specific area of architecture and urban systems, polish your skills and expertise, and launch your career in the field."}], "progress_percentage": 0}', '[{"milestone": "Complete Step 1-2", "reminder": "Review the fundamentals of architecture and urban planning, and explore different styles and materials."}, {"milestone": "Complete Step 3-4", "reminder": "Develop your core skills in architectural design, urban planning, and project management, and apply them to real-world projects."}, {"milestone": "Complete Step 5-6", "reminder": "Specialize in a specific area of architecture and urban systems, polish your skills and expertise, and launch your career in the field."}]', '2026-03-27 06:32:07.623937+00'),
	(15, 39, 'Innovation Consultant', '{"steps": [{"step": 1, "action": "Ignite Your Spark", "description": "As a dynamic generalist, it''s essential to build a strong foundation in creativity, intellectual curiosity, and emotional intelligence. We''ll start by exploring the basics of design thinking and innovation principles. By the end of this phase, you''ll be equipped with the mindset to tackle complex problems and think creatively.", "skills": ["Design Thinking", "Creative Problem-Solving", "Emotional Intelligence"], "courses": [{"name": "Design Thinking Fundamentals", "url": "https://www.coursera.org/learn/design-thinking"}, {"name": "Introduction to Creativity and Innovation", "url": "https://www.youtube.com/watch?v=k1dxQ6ZL1XU"}], "project": {"name": "Innovation Challenge", "description": "Develop a solution to a real-world problem using design thinking principles", "tools": ["Mural", "Figma"], "parameters": ["User-centered design", "Prototype iteration"]}, "detailed_task": "Complete the Design Thinking Fundamentals course on Coursera and apply the principles to a personal project, documenting your process and outcomes", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Discover", "description": "Now that we''ve ignited your spark, it''s time to explore various fields and industries to discover where your passions lie. We''ll delve into the world of innovation, entrepreneurship, and technology to broaden your horizons. By the end of this phase, you''ll have a better understanding of the landscape and be able to identify areas that excite you.", "skills": ["Industry Research", "Trend Analysis", "Networking"], "courses": [{"name": "Introduction to Entrepreneurship", "url": "https://www.udemy.com/course/entrepreneurship-101/"}, {"name": "The Future of Work", "url": "https://www.youtube.com/watch?v=5Klnq5q7b9c"}], "project": {"name": "Industry Insights Report", "description": "Research and analyze a specific industry, identifying trends and opportunities for innovation", "tools": ["Google Trends", "LinkedIn"], "parameters": ["Market analysis", "Competitor research"]}, "detailed_task": "Attend at least 3 webinars or online conferences related to innovation and entrepreneurship, taking detailed notes and reflecting on your learnings", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Develop Your Craft", "description": "As you''ve explored various fields, it''s time to develop your core skills in innovation consulting. We''ll focus on building your expertise in areas like problem-solving, communication, and collaboration. By the end of this phase, you''ll be equipped with the skills to tackle real-world projects and work with clients.", "skills": ["Problem-Solving", "Communication", "Collaboration"], "courses": [{"name": "Effective Communication", "url": "https://www.coursera.org/learn/effective-communication"}, {"name": "Collaboration and Teamwork", "url": "https://www.youtube.com/watch?v=6G8X8F1RjMg"}], "project": {"name": "Innovation Project", "description": "Develop a comprehensive innovation strategy for a real-world client or case study", "tools": ["Asana", "Trello"], "parameters": ["Project management", "Stakeholder engagement"]}, "detailed_task": "Participate in at least 2 group projects or hackathons, taking on a leadership role and applying your skills in problem-solving and collaboration", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Build Your Network", "description": "Now that you''ve developed your craft, it''s essential to build a strong network of professionals in the innovation consulting field. We''ll focus on attending events, conferences, and networking sessions to connect with like-minded individuals and thought leaders. By the end of this phase, you''ll have a robust network and be able to leverage it for future opportunities.", "skills": ["Networking", "Relationship-Building", "Personal Branding"], "courses": [{"name": "Personal Branding", "url": "https://www.udemy.com/course/personal-branding/"}, {"name": "Networking for Introverts", "url": "https://www.youtube.com/watch?v=3B7Y8TQkGxM"}], "project": {"name": "Professional Online Presence", "description": "Create a strong online presence, including a professional website or LinkedIn profile", "tools": ["WordPress", "LinkedIn"], "parameters": ["Personal branding", "Content creation"]}, "detailed_task": "Attend at least 5 networking events or conferences, connecting with at least 10 professionals in the innovation consulting field and following up with them to build relationships", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Polish", "description": "As you''ve built your network and developed your skills, it''s time to specialize in a specific area of innovation consulting. We''ll focus on advanced topics like digital transformation, sustainability, or social innovation. By the end of this phase, you''ll have a deep understanding of your chosen specialty and be able to apply it to real-world projects.", "skills": ["Digital Transformation", "Sustainability", "Social Innovation"], "courses": [{"name": "Digital Transformation", "url": "https://www.coursera.org/learn/digital-transformation"}, {"name": "Sustainability and Social Innovation", "url": "https://www.youtube.com/watch?v=KkKu3kzX8hQ"}], "project": {"name": "Specialized Innovation Project", "description": "Develop a comprehensive innovation strategy for a real-world client or case study, focusing on your chosen specialty", "tools": ["Tableau", "Power BI"], "parameters": ["Data analysis", "Storytelling"]}, "detailed_task": "Complete a specialized course or certification program, applying your learnings to a real-world project or case study", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "As you''ve specialized and polished your skills, it''s time to launch your career as an innovation consultant. We''ll focus on creating a strong portfolio, preparing for interviews, and landing your first client or job. By the end of this phase, you''ll be a confident and competent innovation consultant, ready to take on the world.", "skills": ["Portfolio Development", "Interview Preparation", "Client Acquisition"], "courses": [{"name": "Portfolio Development", "url": "https://www.udemy.com/course/portfolio-development/"}, {"name": "Innovation Consulting Interview Prep", "url": "https://www.youtube.com/watch?v=4KuYxLXKw5g"}], "project": {"name": "Professional Portfolio", "description": "Create a comprehensive portfolio showcasing your skills, experience, and achievements as an innovation consultant", "tools": ["Wix", "Behance"], "parameters": ["Storytelling", "Visual design"]}, "detailed_task": "Prepare for and participate in at least 3 job interviews or client pitches, using your portfolio and skills to demonstrate your value as an innovation consultant", "timeline": "Months 16-18", "completed": false}], "internships": ["Innovation Consultant Intern at Accenture", "Design Thinking Intern at IBM"], "career_outlook": {"salary_range": "INR 8-15 lakhs per annum (entry-level) to INR 25-40 lakhs per annum (senior-level)", "top_companies": ["Accenture", "Deloitte", "IBM"], "hiring_trends": "The demand for innovation consultants is on the rise, with companies looking for professionals who can drive growth, improve efficiency, and foster a culture of innovation. Recruiters are looking for candidates with strong problem-solving skills, creativity, and the ability to collaborate with cross-functional teams. As the industry continues to evolve, innovation consultants will play a crucial role in shaping the future of business and society.", "future_scope": "The innovation consulting field is expected to grow exponentially in the next decade, driven by the increasing need for companies to innovate and stay ahead of the curve. With the rise of digital transformation, sustainability, and social innovation, the demand for skilled innovation consultants will continue to rise, making it a high-growth and secure career path for the future."}, "reminders": [{"milestone": "Complete Design Thinking Fundamentals course", "reminder": "Months 1-3"}, {"milestone": "Attend at least 3 webinars or online conferences", "reminder": "Months 4-6"}, {"milestone": "Participate in at least 2 group projects or hackathons", "reminder": "Months 7-9"}, {"milestone": "Attend at least 5 networking events or conferences", "reminder": "Months 10-12"}, {"milestone": "Complete specialized course or certification program", "reminder": "Months 13-15"}, {"milestone": "Prepare for and participate in at least 3 job interviews or client pitches", "reminder": "Months 16-18"}]}', '[{"milestone": "Complete Design Thinking Fundamentals course", "reminder": "Months 1-3"}, {"milestone": "Attend at least 3 webinars or online conferences", "reminder": "Months 4-6"}, {"milestone": "Participate in at least 2 group projects or hackathons", "reminder": "Months 7-9"}, {"milestone": "Attend at least 5 networking events or conferences", "reminder": "Months 10-12"}, {"milestone": "Complete specialized course or certification program", "reminder": "Months 13-15"}, {"milestone": "Prepare for and participate in at least 3 job interviews or client pitches", "reminder": "Months 16-18"}]', '2026-04-01 18:04:32.894946+00'),
	(18, 19, 'Entrepreneur/Founder', '{"steps": [{"step": 1, "action": "Spark the Flame", "description": "We''re starting from the basics, and it''s essential to understand the fundamentals of entrepreneurship, including business models, market research, and financial planning. As an Adaptive Explorer, you''ll thrive in an environment that encourages experimentation and learning. You''ll begin to develop a strong foundation in entrepreneurship, which will serve as the bedrock for your future endeavors.", "skills": ["Business Modeling", "Market Research", "Financial Planning"], "courses": [{"name": "How to Start a Startup", "url": "https://www.youtube.com/watch?v=CBYhVcO4CWw"}, {"name": "Entrepreneurship 101", "url": "https://www.coursera.org/learn/entrepreneurship-101"}], "project": {"name": "Business Idea Generator", "description": "Create a simple web application that generates business ideas based on user input, such as industry, target audience, and revenue model.", "tools": ["Python", "Flask"], "parameters": ["User Engagement", "Idea Validation"]}, "detailed_task": "Research and create a list of 10 successful startups, analyze their business models, and identify common patterns and trends.", "timeline": "Months 1-3", "completed": true}, {"step": 2, "action": "Build the Foundation", "description": "Now that we''ve sparked the flame, it''s time to build a strong foundation in entrepreneurship. You''ll learn about leadership, team management, and communication skills, which are essential for any successful entrepreneur. As an Ambivert, you''ll need to balance your introverted and extroverted tendencies to effectively lead and manage teams.", "skills": ["Leadership", "Team Management", "Communication"], "courses": [{"name": "Leadership and Team Management", "url": "https://www.youtube.com/watch?v=d9y7yPWV8eo"}, {"name": "Effective Communication", "url": "https://www.udemy.com/course/effective-communication/"}], "project": {"name": "Team Management Simulator", "description": "Create a simple simulation game that teaches team management skills, such as resource allocation, prioritization, and conflict resolution.", "tools": ["JavaScript", "Phaser"], "parameters": ["Team Performance", "Resource Optimization"]}, "detailed_task": "Create a personal leadership manifesto, outlining your values, vision, and goals as an entrepreneur.", "timeline": "Months 4-6", "completed": true}, {"step": 3, "action": "Explore the Ecosystem", "description": "As an Adaptive Explorer, you''re naturally curious and enthusiastic about exploring new ideas and ecosystems. You''ll learn about the startup ecosystem, including accelerators, incubators, and venture capital firms. You''ll also start building your professional network, which is crucial for any entrepreneur.", "skills": ["Startup Ecosystem", "Networking", "Pitching"], "courses": [{"name": "Startup Ecosystem 101", "url": "https://www.youtube.com/watch?v=7NfTd1z2xdk"}, {"name": "Networking for Entrepreneurs", "url": "https://www.coursera.org/learn/networking-entrepreneurs"}], "project": {"name": "Startup Directory", "description": "Create a comprehensive directory of startups, accelerators, and incubators in your region, including their focus areas, funding, and notable achievements.", "tools": ["Airtable", "Google Maps"], "parameters": ["Startup Discovery", "Ecosystem Mapping"]}, "detailed_task": "Attend at least 3 startup events, conferences, or meetups, and connect with at least 10 entrepreneurs, investors, or industry experts.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Develop Your Skills", "description": "As an entrepreneur, you''ll need to wear many hats, and developing a wide range of skills is crucial for success. You''ll focus on building your expertise in areas such as marketing, sales, and product development. You''ll also start to develop a specialization, which will help you stand out in the market.", "skills": ["Marketing", "Sales", "Product Development"], "courses": [{"name": "Digital Marketing Course", "url": "https://www.youtube.com/watch?v=0Bis4ZqVCVQ"}, {"name": "Sales and Business Development", "url": "https://www.udemy.com/course/sales-and-business-development/"}], "project": {"name": "Marketing Campaign", "description": "Create a comprehensive marketing campaign for a startup, including social media marketing, content marketing, and paid advertising.", "tools": ["Adobe Creative Cloud", "HubSpot"], "parameters": ["Campaign Reach", "Conversion Rate"]}, "detailed_task": "Conduct a market research project, analyzing consumer behavior, market trends, and competitor analysis for a specific industry or niche.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Refine", "description": "As you progress in your entrepreneurial journey, it''s essential to specialize and refine your skills. You''ll focus on developing a deep understanding of your industry, including the latest trends, technologies, and best practices. You''ll also start to build a professional portfolio, which will showcase your expertise and accomplishments.", "skills": ["Industry Expertise", "Portfolio Building", "Thought Leadership"], "courses": [{"name": "Industry Trends and Insights", "url": "https://www.youtube.com/watch?v=Q4Fk1e9q2hI"}, {"name": "Building a Professional Portfolio", "url": "https://www.coursera.org/learn/portfolio-building"}], "project": {"name": "Industry Report", "description": "Create a comprehensive industry report, analyzing the latest trends, technologies, and best practices in your specialized area.", "tools": ["Tableau", "Google Analytics"], "parameters": ["Report Quality", "Insight Depth"]}, "detailed_task": "Develop a thought leadership piece, such as a blog post, podcast, or video series, showcasing your expertise and sharing your insights with the community.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch and Scale", "description": "You''ve made it to the final step, and now it''s time to launch and scale your entrepreneurial venture. You''ll focus on developing a go-to-market strategy, building a team, and securing funding. You''ll also start to think about scaling your business, including expanding your customer base, increasing revenue, and exploring new markets.", "skills": ["Go-to-Market Strategy", "Team Building", "Funding"], "courses": [{"name": "Go-to-Market Strategy", "url": "https://www.youtube.com/watch?v=KdVWGXK6kQw"}, {"name": "Funding and Venture Capital", "url": "https://www.udemy.com/course/funding-and-venture-capital/"}], "project": {"name": "Business Launch Plan", "description": "Create a comprehensive business launch plan, including a go-to-market strategy, team building, and funding plan.", "tools": ["Asana", "Trello"], "parameters": ["Launch Timeline", "Team Performance"]}, "detailed_task": "Develop a pitches deck, practicing your pitch and presentation skills, and preparing to pitch your business to investors, customers, or partners.", "timeline": "Months 16-18", "completed": false}], "internships": ["Startup Accelerator Intern", "Venture Capital Firm Intern"], "career_outlook": {"salary_range": "INR 8-20 lakhs per annum (entry-level) to INR 50-100 lakhs per annum (senior-level)", "top_companies": ["Flipkart", "Ola", "Paytm"], "hiring_trends": "The demand for entrepreneurs and founders is on the rise, with many startups and venture capital firms looking for talented individuals to lead and grow their businesses. Recruiters look for skills such as leadership, teamwork, and adaptability, as well as a strong understanding of the industry and market trends.", "future_scope": "The career outlook for entrepreneurs and founders is highly promising, with many opportunities for growth, innovation, and impact. As the startup ecosystem continues to evolve, the demand for skilled entrepreneurs will only increase, making this a high-growth and safe-bet career path for the next decade."}, "reminders": [{"milestone": "Complete Step 1-2", "reminder": "Review and practice your business modeling, market research, and financial planning skills."}, {"milestone": "Complete Step 3-4", "reminder": "Network and build relationships with entrepreneurs, investors, and industry experts."}], "progress_percentage": 33}', '[{"milestone": "Complete Step 1-2", "reminder": "Review and practice your business modeling, market research, and financial planning skills."}, {"milestone": "Complete Step 3-4", "reminder": "Network and build relationships with entrepreneurs, investors, and industry experts."}]', '2026-04-04 07:56:41.097063+00'),
	(16, 41, 'Research Scientist', '{"steps": [{"step": 1, "action": "Spark Curiosity", "description": "The first step towards becoming a Research Scientist is to develop a strong foundation in the sciences, mathematics, and critical thinking. You will learn to approach problems with a curious and analytical mindset, setting the stage for a lifelong journey of discovery. By cultivating this mindset, you''ll be better equipped to tackle complex challenges and explore new ideas.", "skills": ["Scientific Method", "Data Analysis", "Research Techniques"], "courses": [{"name": "Introduction to Research Methods", "url": "https://www.coursera.org/learn/research-methods"}, {"name": "Science and Technology for Global Challenges", "url": "https://www.youtube.com/watch?v=dhKBLt7hjRk"}], "project": {"name": "Science Fair Project", "description": "Design and conduct an experiment to investigate a scientific phenomenon, collecting and analyzing data to draw meaningful conclusions.", "tools": ["Microsoft Excel", "Google Scholar"], "parameters": ["Hypothesis Testing", "Data Visualization"]}, "detailed_task": "Conduct a thorough literature review on a topic of interest, identifying key research questions and methodologies used in the field.", "timeline": "Months 1-3", "completed": true}, {"step": 2, "action": "Build Foundations", "description": "Now that you''ve sparked your curiosity, it''s time to build a solid foundation in the sciences and mathematics. You''ll delve into the fundamentals of physics, chemistry, biology, and mathematics, developing a strong understanding of the principles and concepts that underlie research in these fields. By mastering these foundations, you''ll be well-prepared to tackle more advanced topics and explore new areas of interest.", "skills": ["Python Programming", "Statistics", "Laboratory Techniques"], "courses": [{"name": "Python for Everybody", "url": "https://www.coursera.org/specializations/python"}, {"name": "Introduction to Statistics", "url": "https://www.khanacademy.org/math/statistics"}], "project": {"name": "Lab Report Analysis", "description": "Analyze and interpret the results of a laboratory experiment, using statistical techniques to draw conclusions and identify areas for further investigation.", "tools": ["R Studio", "IBM SPSS"], "parameters": ["Data Cleaning", "Hypothesis Testing"]}, "detailed_task": "Create a comprehensive study plan, outlining key concepts, study materials, and practice problems for upcoming exams and assessments.", "timeline": "Months 4-6", "completed": true}, {"step": 3, "action": "Explore Specializations", "description": "With a strong foundation in place, you''re now ready to explore specializations within the field of research science. You''ll delve into topics such as materials science, biotechnology, or environmental science, developing a deeper understanding of the concepts, techniques, and applications that define these areas. By exploring these specializations, you''ll begin to identify areas of interest and develop a sense of direction for your future research pursuits.", "skills": ["Research Design", "Data Visualization", "Scientific Communication"], "courses": [{"name": "Materials Science and Engineering", "url": "https://www.edx.org/course/materials-science"}, {"name": "Introduction to Biotechnology", "url": "https://www.youtube.com/watch?v=j-1rZQpPZgk"}], "project": {"name": "Research Proposal", "description": "Develop a research proposal outlining a clear question, methodology, and expected outcomes, demonstrating your ability to design and conduct original research.", "tools": ["LaTeX", "EndNote"], "parameters": ["Literature Review", "Methodology Development"]}, "detailed_task": "Attend a research conference or seminar, taking detailed notes and reflecting on the presentations and discussions.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Network and Collaborate", "description": "As you continue to develop your skills and knowledge, it''s essential to network and collaborate with others in the field. You''ll participate in research projects, join professional organizations, and engage with online communities, fostering relationships and learning from the experiences of others. By building a professional network, you''ll expand your opportunities for collaboration, mentorship, and career advancement.", "skills": ["Teamwork and Communication", "Project Management", "Grant Writing"], "courses": [{"name": "Collaboration and Teamwork", "url": "https://www.coursera.org/specializations/teamwork"}, {"name": "Introduction to Project Management", "url": "https://www.udemy.com/course/project-management/"}], "project": {"name": "Group Research Project", "description": "Collaborate with a team to design, conduct, and present a research project, developing your skills in teamwork, communication, and project management.", "tools": ["Trello", "Slack"], "parameters": ["Project Planning", "Data Sharing"]}, "detailed_task": "Create a professional online presence, including a LinkedIn profile and personal website or blog, to showcase your skills and research experience.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Refine", "description": "With a strong foundation and network in place, you''re now ready to specialize and refine your skills in a specific area of research science. You''ll delve deeper into advanced topics, developing a high level of expertise and preparing yourself for leadership roles or specialized positions. By specializing and refining your skills, you''ll enhance your career prospects and increase your potential for making meaningful contributions to the field.", "skills": ["Advanced Data Analysis", "Machine Learning", "Research Ethics"], "courses": [{"name": "Advanced Data Analysis", "url": "https://www.coursera.org/specializations/data-analysis"}, {"name": "Machine Learning for Researchers", "url": "https://www.youtube.com/watch?v=7G5d9Bm1b8E"}], "project": {"name": "Original Research Manuscript", "description": "Conduct original research and prepare a manuscript for publication in a peer-reviewed journal, demonstrating your expertise and ability to contribute to the scientific literature.", "tools": ["R Markdown", "GitHub"], "parameters": ["Literature Review", "Methodology Development"]}, "detailed_task": "Develop a comprehensive portfolio of your research experience, including papers, presentations, and projects, to showcase your skills and expertise.", "timeline": "Months 13-18", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "With your skills refined and your portfolio in place, you''re now ready to launch your career as a research scientist. You''ll apply for jobs, internships, or graduate programs, leveraging your network and expertise to secure opportunities and advance your career. By launching your career, you''ll begin to make meaningful contributions to the field, applying your knowledge and skills to drive innovation and progress.", "skills": ["Career Development", "Professional Networking", "Grant Writing"], "courses": [{"name": "Career Development for Researchers", "url": "https://www.coursera.org/specializations/career-development"}, {"name": "Professional Networking for Researchers", "url": "https://www.youtube.com/watch?v=Q5zP5R9Q1cA"}], "project": {"name": "Career Development Plan", "description": "Create a comprehensive plan outlining your career goals, strategies, and timelines, including job applications, networking, and professional development.", "tools": ["LinkedIn", "Resume.io"], "parameters": ["Job Search Strategies", "Professional Online Presence"]}, "detailed_task": "Prepare for and attend a job interview, using your skills and experience to showcase your potential as a research scientist.", "timeline": "Months 19-24", "completed": false}], "internships": ["Research Intern at a University Laboratory", "Science Policy Intern at a Government Agency"], "career_outlook": {"salary_range": "INR 50,000 - 200,000 per month (depending on experience and location)", "top_companies": ["Council of Scientific and Industrial Research (CSIR)", "Indian Institute of Technology (IIT)", "Tata Institute of Fundamental Research (TIFR)"], "hiring_trends": "Research scientists are in high demand across various industries, including academia, government, and private sectors. Recruiters look for candidates with strong research skills, attention to detail, and the ability to communicate complex ideas effectively. The field is expected to grow significantly, with new technologies and innovations driving the need for skilled researchers.", "future_scope": "The career of a research scientist is a safe bet for the next decade, with ample opportunities for growth, innovation, and contributions to society. As technology advances and new challenges emerge, the demand for skilled researchers will continue to rise, making this a high-growth career path with a bright future."}, "reminders": [{"milestone": "Complete Step 1-2", "reminder": "Review and practice scientific concepts regularly, staying up-to-date with the latest developments in the field."}, {"milestone": "Complete Step 3-4", "reminder": "Network and collaborate with peers and professionals, attending conferences and seminars to stay current with industry trends."}, {"milestone": "Complete Step 5-6", "reminder": "Refine your skills and portfolio, preparing for job applications and graduate programs by showcasing your expertise and experience."}], "progress_percentage": 33}', '[{"milestone": "Complete Step 1-2", "reminder": "Review and practice scientific concepts regularly, staying up-to-date with the latest developments in the field."}, {"milestone": "Complete Step 3-4", "reminder": "Network and collaborate with peers and professionals, attending conferences and seminars to stay current with industry trends."}, {"milestone": "Complete Step 5-6", "reminder": "Refine your skills and portfolio, preparing for job applications and graduate programs by showcasing your expertise and experience."}]', '2026-04-02 06:11:41.985065+00'),
	(17, 42, 'Human-Computer Interaction (HCI) Design', '{"steps": [{"step": 1, "action": "Laying Foundations", "description": "We start by understanding the basics of Human-Computer Interaction (HCI) Design, which includes principles of design, human factors, and technical skills. This step is crucial for building a strong foundation in HCI. You''ll begin to appreciate the intricacies of user experience and how to create intuitive designs.", "skills": ["User Research", "Wireframing", "Visual Design Principles"], "courses": [{"name": "Human-Computer Interaction by Georgia Tech", "url": "https://www.coursera.org/learn/human-computer-interaction"}, {"name": "Introduction to User Experience Design by Udemy", "url": "https://www.udemy.com/course/introduction-to-user-experience-design/"}], "project": {"name": "UX Diary", "description": "Design a daily diary app focusing on user experience and simplicity.", "tools": ["Figma", "Adobe XD"], "parameters": ["User Engagement", "Navigation Efficiency"]}, "detailed_task": "Create a low-fidelity prototype of the diary app, considering user flows and wireframes.", "timeline": "Months 1-3", "completed": true}, {"step": 2, "action": "Exploring Design Tools", "description": "Now, we dive deeper into the design tools and technologies used in HCI. This step is vital for becoming proficient in the software and methodologies that are industry standards. You''ll learn to navigate through design systems, create high-fidelity prototypes, and conduct usability testing.", "skills": ["Prototyping", "Usability Testing", "Interaction Design"], "courses": [{"name": "Design Systems by Airbnb on YouTube", "url": "https://www.youtube.com/watch?v=bG1lVQ7qxlw"}, {"name": "Interaction Design by Coursera", "url": "https://www.coursera.org/specializations/interaction-design"}], "project": {"name": "EcoPal", "description": "Design an interactive mobile app for tracking and reducing personal carbon footprint.", "tools": ["Sketch", "InVision"], "parameters": ["Sustainability Features", "UI Responsiveness"]}, "detailed_task": "Develop a functional prototype of EcoPal, emphasizing on user interaction and feedback mechanisms.", "timeline": "Months 4-6", "completed": true}, {"step": 3, "action": "Building Core Skills", "description": "At this stage, we focus on enhancing your ability to apply HCI principles to real-world problems. This involves understanding user needs, developing solutions, and evaluating design effectiveness. You''ll start to build a portfolio of projects that demonstrate your skills in HCI.", "skills": ["Design Thinking", "User Interviewing", "Heuristic Evaluation"], "courses": [{"name": "Design Thinking by MIT on edX", "url": "https://www.edx.org/course/design-thinking"}, {"name": "User Research by Nielsen Norman Group", "url": "https://www.nngroup.com/courses/user-research/"}], "project": {"name": "FitMind", "description": "Create a mental health support platform, focusing on accessibility and user support features.", "tools": ["Adobe Creative Cloud", "Figma"], "parameters": ["Accessibility Features", "Content Strategy"]}, "detailed_task": "Conduct user research for FitMind, including interviews and surveys, to understand the needs of the target audience.", "timeline": "Months 7-9", "completed": true}, {"step": 4, "action": "Networking and Portfolio Building", "description": "Here, we emphasize the importance of networking within the HCI community and building a professional portfolio. This step is crucial for getting recognized by potential employers and staying updated with industry trends. You''ll learn how to present your projects effectively and engage with professionals in the field.", "skills": ["Portfolio Development", "Networking", "Design Critique"], "courses": [{"name": "Portfolio Development by LinkedIn Learning", "url": "https://www.linkedin.com/learning/portfolio-development-for-designers"}, {"name": "Design Communities by Design Systems Coalition", "url": "https://www.designsystemscoalition.com/communities/"}], "project": {"name": "Personal Portfolio Site", "description": "Design and develop a personal portfolio website showcasing your projects and skills in HCI.", "tools": ["WordPress", "Webflow"], "parameters": ["SEO Optimization", "Responsive Design"]}, "detailed_task": "Create a case study for one of your projects, highlighting the design process, challenges, and outcomes.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialization and Mastery", "description": "Now, we delve into specialized areas of HCI, such as accessibility, AI, or augmented reality. This step is about mastering your skills and becoming an expert in a specific domain. You''ll explore the latest technologies and methodologies, preparing yourself for advanced roles in HCI.", "skills": ["Accessible Design", "Designing for AI", "AR/VR Design"], "courses": [{"name": "Accessible Design by W3Cx on edX", "url": "https://www.edx.org/course/web-accessibility"}, {"name": "Designing for AI by Google on Coursera", "url": "https://www.coursera.org/specializations/designing-ai"}], "project": {"name": "MindPalace", "description": "Develop an AR-based mental wellness platform, incorporating AI-driven personalized recommendations.", "tools": ["Unity", "ARKit"], "parameters": ["AR Interaction Design", "AI Ethics"]}, "detailed_task": "Research and implement accessible design features in MindPalace, ensuring inclusive user experience.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Job Readiness and Launch", "description": "In the final step, we prepare you for the job market, focusing on resume building, interview preparation, and professional networking. This is about launching your career in HCI with confidence and readiness. You''ll learn how to articulate your skills and experiences to potential employers and navigate the hiring process effectively.", "skills": ["Resume Writing", "Interview Preparation", "Professional Networking"], "courses": [{"name": "Resume Writing for Designers by LinkedIn Learning", "url": "https://www.linkedin.com/learning/resume-writing-for-designers"}, {"name": "Design Interview Prep by Glassdoor", "url": "https://www.glassdoor.com/blog/design-interview-prep/"}], "project": {"name": "Career Launch Kit", "description": "Assemble a comprehensive career launch kit, including a refined portfolio, resume, and cover letter.", "tools": ["Adobe InDesign", "LinkedIn"], "parameters": ["Personal Branding", "Career Storytelling"]}, "detailed_task": "Practice whiteboarding exercises and common HCI design interview questions to improve your interview skills.", "timeline": "Months 16-18", "completed": false}], "internships": ["UX Design Intern at Google", "Human-Computer Interaction Intern at Microsoft"], "career_outlook": {"salary_range": "USD 80,000 - 150,000 per year", "top_companies": ["Apple", "Amazon", "Facebook"], "hiring_trends": "The demand for HCI designers is on the rise, especially with the growth of digital products and services. Recruiters look for candidates with a strong portfolio, proficiency in design tools, and excellent understanding of user-centered design principles. Current trends include the integration of AI, accessibility, and sustainability in design. Companies are seeking designers who can create innovative, user-friendly, and socially responsible experiences.", "future_scope": "HCI design is a future-proof career, with continuous growth and evolution in technology and user needs. As digital transformation advances, the role of HCI designers will become even more critical in shaping how humans interact with technology, making it a high-growth path for the next decade."}, "reminders": [{"milestone": "Complete the foundation courses", "reminder": "Review the courses in Step 1 and ensure you''ve completed them before moving forward."}, {"milestone": "Develop a portfolio", "reminder": "Regularly update your portfolio with new projects and skills, and seek feedback from mentors or peers."}], "progress_percentage": 50}', '[{"milestone": "Complete the foundation courses", "reminder": "Review the courses in Step 1 and ensure you''ve completed them before moving forward."}, {"milestone": "Develop a portfolio", "reminder": "Regularly update your portfolio with new projects and skills, and seek feedback from mentors or peers."}]', '2026-04-02 09:46:29.959791+00'),
	(19, 7, 'Environmental Science', '{"steps": [{"step": 1, "action": "Discover Your Environmental Calling", "description": "This step matters because it helps you understand the basics of environmental science and its various fields, such as conservation, sustainability, and ecology. You''ll learn about the importance of environmental science and how it impacts our daily lives. By exploring your interests and strengths, you''ll be able to identify areas where you can make a meaningful contribution.", "skills": ["Basic Ecology", "Environmental Awareness", "Research Skills"], "courses": [{"name": "Introduction to Environmental Science", "url": "https://www.coursera.org/learn/environmental-science"}, {"name": "Environmental Science 101", "url": "https://www.youtube.com/watch?v=9x9G2Q9AKB4"}], "project": {"name": "Eco-Footprint Calculator", "description": "Create a simple calculator to measure the environmental impact of daily activities, such as energy consumption and waste generation.", "tools": ["Microsoft Excel", "Google Sheets"], "parameters": ["Carbon footprint", "Water usage", "Waste management"]}, "detailed_task": "Research and list 10 environmental issues affecting your local community, and propose potential solutions for each issue.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Build Your Foundation in Science", "description": "This step is crucial because it helps you develop a strong foundation in scientific principles, such as biology, chemistry, and physics, which are essential for environmental science. You''ll learn about the scientific method, experimentation, and data analysis. By building a strong foundation in science, you''ll be better equipped to tackle complex environmental issues.", "skills": ["Biology Fundamentals", "Chemistry Basics", "Data Analysis"], "courses": [{"name": "Biology 101", "url": "https://www.khanacademy.org/science/biology"}, {"name": "Chemistry Basics", "url": "https://www.youtube.com/watch?v=3VmRpkov9xA"}], "project": {"name": "Water Quality Monitoring", "description": "Design and conduct an experiment to test the water quality of a local water source, using parameters such as pH, turbidity, and nutrient levels.", "tools": ["Water testing kits", "Microscope"], "parameters": ["pH levels", "Turbidity", "Nutrient levels"]}, "detailed_task": "Conduct a literature review on the impact of climate change on local ecosystems, and present your findings in a short report.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Explore Core Environmental Concepts", "description": "This step matters because it helps you delve deeper into core environmental concepts, such as conservation, sustainability, and environmental policy. You''ll learn about the importance of biodiversity, ecosystem services, and human-environment interactions. By exploring these concepts, you''ll be able to develop a more nuanced understanding of environmental issues and potential solutions.", "skills": ["Conservation Biology", "Sustainability Principles", "Environmental Policy"], "courses": [{"name": "Conservation Biology", "url": "https://www.coursera.org/learn/conservation-biology"}, {"name": "Sustainability Principles", "url": "https://www.edx.org/learn/sustainability"}], "project": {"name": "Sustainable Development Plan", "description": "Develop a plan for sustainable development in a local community, incorporating environmental, social, and economic factors.", "tools": ["GIS software", "Stakeholder engagement techniques"], "parameters": ["Economic viability", "Social equity", "Environmental impact"]}, "detailed_task": "Research and analyze a successful environmental project or initiative, and present your findings in a case study.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Develop Practical Skills in Environmental Science", "description": "This step is important because it helps you develop practical skills in environmental science, such as fieldwork, laboratory analysis, and data interpretation. You''ll learn about the importance of hands-on experience and how to apply theoretical knowledge to real-world problems. By developing practical skills, you''ll be better equipped to collect and analyze data, and communicate your findings effectively.", "skills": ["Fieldwork Techniques", "Laboratory Analysis", "Data Interpretation"], "courses": [{"name": "Fieldwork Techniques", "url": "https://www.udemy.com/course/fieldwork-techniques"}, {"name": "Laboratory Analysis", "url": "https://www.youtube.com/watch?v=QxL4hMlLwQI"}], "project": {"name": "Environmental Impact Assessment", "description": "Conduct an environmental impact assessment for a proposed development project, using fieldwork and laboratory analysis to collect and analyze data.", "tools": ["Field equipment", "Laboratory software"], "parameters": ["Air quality", "Water quality", "Soil contamination"]}, "detailed_task": "Develop a research proposal on an environmental topic of your choice, and present it to a panel of peers and mentors.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize in a Niche Area", "description": "This step matters because it helps you specialize in a niche area of environmental science, such as climate change, conservation biology, or environmental policy. You''ll learn about the latest developments and advancements in your chosen area, and develop a deeper understanding of the complex issues and challenges. By specializing in a niche area, you''ll be able to develop a unique set of skills and expertise that will make you more competitive in the job market.", "skills": ["Climate Change Mitigation", "Conservation Biology", "Environmental Policy Analysis"], "courses": [{"name": "Climate Change Mitigation", "url": "https://www.coursera.org/learn/climate-change-mitigation"}, {"name": "Conservation Biology", "url": "https://www.edx.org/learn/conservation-biology"}], "project": {"name": "Climate Change Adaptation Plan", "description": "Develop a climate change adaptation plan for a local community, incorporating strategies for mitigation, adaptation, and resilience.", "tools": ["Climate modeling software", "Stakeholder engagement techniques"], "parameters": ["Temperature increase", "Sea-level rise", "Extreme weather events"]}, "detailed_task": "Develop a comprehensive portfolio of your work, including research papers, project reports, and presentations, and showcase it to potential employers or graduate schools.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career in Environmental Science", "description": "This step is crucial because it helps you launch your career in environmental science, by developing a professional network, building a strong resume and cover letter, and preparing for job interviews. You''ll learn about the job market, industry trends, and the skills and qualifications required for different roles. By launching your career, you''ll be able to apply your knowledge and skills to make a positive impact in the environmental sector.", "skills": ["Professional Networking", "Resume Building", "Job Interview Preparation"], "courses": [{"name": "Professional Networking", "url": "https://www.linkedin.com/learning/professional-networking"}, {"name": "Resume Building", "url": "https://www.youtube.com/watch?v=jmJy8Fz4wBQ"}], "project": {"name": "Career Development Plan", "description": "Develop a career development plan, incorporating short-term and long-term goals, and strategies for achieving them.", "tools": ["Career assessment tools", "Job search platforms"], "parameters": ["Job title", "Industry", "Location"]}, "detailed_task": "Attend a professional conference or workshop in environmental science, and present a poster or give a presentation on your research or project work.", "timeline": "Months 16-18", "completed": false}], "internships": ["Environmental Consultant at a government agency or private company", "Research Assistant at a university or research institution"], "career_outlook": {"salary_range": "Entry-level: $40,000 - $60,000 per year, Senior-level: $80,000 - $120,000 per year", "top_companies": ["Environmental Protection Agency (EPA)", "World Wildlife Fund (WWF)", "The Nature Conservancy"], "hiring_trends": "The demand for environmental scientists and specialists is expected to grow 8% from 2020 to 2030, faster than the average for all occupations. Employers are looking for candidates with strong technical skills, such as data analysis and programming, as well as soft skills, such as communication and teamwork. The trend is towards more emphasis on sustainability, climate change, and environmental policy, and companies are looking for professionals who can help them navigate these complex issues.", "future_scope": "The field of environmental science is expected to continue growing, with a focus on sustainability, climate change, and environmental policy. As the world becomes more aware of the importance of environmental protection, the demand for environmental scientists and specialists is expected to increase, making it a safe bet for a career with a high growth potential."}, "reminders": [{"milestone": "Complete Step 1-2", "reminder": "Make sure to research and list 10 environmental issues affecting your local community, and propose potential solutions for each issue."}, {"milestone": "Complete Step 3-4", "reminder": "Develop a plan for sustainable development in a local community, incorporating environmental, social, and economic factors."}, {"milestone": "Complete Step 5-6", "reminder": "Develop a comprehensive portfolio of your work, including research papers, project reports, and presentations, and showcase it to potential employers or graduate schools."}]}', '[{"milestone": "Complete Step 1-2", "reminder": "Make sure to research and list 10 environmental issues affecting your local community, and propose potential solutions for each issue."}, {"milestone": "Complete Step 3-4", "reminder": "Develop a plan for sustainable development in a local community, incorporating environmental, social, and economic factors."}, {"milestone": "Complete Step 5-6", "reminder": "Develop a comprehensive portfolio of your work, including research papers, project reports, and presentations, and showcase it to potential employers or graduate schools."}]', '2026-04-08 05:38:49.941241+00'),
	(20, 50, 'Research Scientist', '{"steps": [{"step": 1, "action": "Ignite Curiosity", "description": "We start by building a strong foundation in the basics of science and research. You will learn to explore and understand the scientific method, which is crucial for a Research Scientist. By laying this groundwork, you''ll be better equipped to navigate more complex topics in the future.", "skills": ["Scientific Method", "Data Analysis", "Critical Thinking"], "courses": [{"name": "Introduction to Research Methods", "url": "https://www.coursera.org/learn/research-methods"}, {"name": "Data Analysis with Python", "url": "https://www.youtube.com/watch?v=5JnMutdy6Fw"}], "project": {"name": "Science Fair Project", "description": "Design and conduct a simple experiment to test a hypothesis, applying the scientific method.", "tools": ["Python", "Excel"], "parameters": ["Variable Control", "Data Accuracy"]}, "detailed_task": "Conduct a literature review on a topic of interest and design an experiment to test a hypothesis, considering variables and potential biases.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore Disciplines", "description": "Now, we broaden your knowledge by exploring various disciplines that are relevant to research science. You''ll delve into biology, chemistry, physics, and mathematics, gaining a deeper understanding of how they intersect and impact research. This broad perspective will help you identify areas where you''d like to focus your research efforts.", "skills": ["Interdisciplinary Knowledge", "Research Design", "Communication"], "courses": [{"name": "Biology Specialization", "url": "https://www.coursera.org/specializations/biology"}, {"name": "Physics for Scientists and Engineers", "url": "https://www.youtube.com/watch?v=K8huj6qfFrA"}], "project": {"name": "Interdisciplinary Research Review", "description": "Write a review of current research in an area where multiple disciplines intersect, such as environmental science or biotechnology.", "tools": ["Google Scholar", "EndNote"], "parameters": ["Interdisciplinary Approach", "Research Gaps"]}, "detailed_task": "Read and summarize at least 10 research papers from different disciplines, analyzing how they contribute to the broader field of research science.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Build Core Skills", "description": "At this stage, we focus on developing the core skills needed for a Research Scientist, including data analysis, programming, and laboratory techniques. You''ll learn how to design experiments, collect and analyze data, and draw meaningful conclusions. These skills are essential for conducting high-quality research.", "skills": ["Programming in R or Python", "Statistical Analysis", "Lab Techniques"], "courses": [{"name": "R Programming", "url": "https://www.coursera.org/learn/r-programming"}, {"name": "Python for Data Science", "url": "https://www.youtube.com/watch?v=LHBE6vDnPp8"}], "project": {"name": "Data Analysis Project", "description": "Analyze a dataset using statistical methods and programming languages, interpreting the results in the context of a research question.", "tools": ["R", "Python", "Jupyter Notebook"], "parameters": ["Data Quality", "Model Accuracy"]}, "detailed_task": "Complete a series of data analysis exercises using different datasets and tools, focusing on data visualization and interpretation.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Apply to Real-World Problems", "description": "Now, we apply the skills and knowledge you''ve gained to real-world problems. You''ll work on projects that involve designing and conducting experiments, collecting and analyzing data, and communicating your findings. This practical experience will help you develop a deeper understanding of the research process and its applications.", "skills": ["Project Management", "Team Collaboration", "Science Communication"], "courses": [{"name": "Project Management for Researchers", "url": "https://www.coursera.org/learn/project-management"}, {"name": "Science Communication", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}], "project": {"name": "Research Project Proposal", "description": "Develop a proposal for a research project, including a literature review, methodology, and expected outcomes.", "tools": ["Microsoft Office", "LaTeX"], "parameters": ["Feasibility", "Impact"]}, "detailed_task": "Participate in a group project where you design, conduct, and present a research project, emphasizing teamwork, time management, and effective communication.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Network", "description": "At this stage, we focus on specialization within a specific area of research science. You''ll delve deeper into your chosen field, staying updated on the latest research and methodologies. Networking with peers and professionals in your field will also be crucial, as it can lead to collaborations, mentorship, and job opportunities.", "skills": ["Specialized Knowledge", "Networking", "Grant Writing"], "courses": [{"name": "Advanced Topics in Research Science", "url": "https://www.coursera.org/learn/advanced-research-methods"}, {"name": "Networking for Researchers", "url": "https://www.youtube.com/watch?v=JY2q0X1t2Qc"}], "project": {"name": "Research Review Article", "description": "Write a comprehensive review article on recent advancements in your area of specialization, highlighting key findings and future directions.", "tools": ["EndNote", "Google Scholar"], "parameters": ["Comprehensiveness", "Critical Analysis"]}, "detailed_task": "Attend at least two conferences or workshops in your field, presenting your work and engaging with professionals to build your network.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "Finally, we prepare you for the transition into a professional research scientist role. You''ll refine your portfolio, practice your job interview skills, and apply for positions that match your expertise and interests. This is an exciting time, as you''ll be applying all that you''ve learned to real-world challenges.", "skills": ["Job Application", "Interview Preparation", "Career Development"], "courses": [{"name": "Career Development for Researchers", "url": "https://www.coursera.org/learn/career-development"}, {"name": "Job Interview Preparation", "url": "https://www.youtube.com/watch?v=9cVz5NOK4lI"}], "project": {"name": "Professional Portfolio", "description": "Develop a professional portfolio showcasing your research experience, skills, and achievements, tailored to your target job market.", "tools": ["LinkedIn", "GitHub"], "parameters": ["Clarity", "Relevance"]}, "detailed_task": "Apply for at least five job positions, tailoring your application materials for each, and prepare for interviews by practicing common questions and your presentation skills.", "timeline": "Months 16-18", "completed": false}], "internships": ["Research Assistant", "Laboratory Technician"], "career_outlook": {"salary_range": "Entry-level: $50,000 - $70,000 per year; Senior: $100,000 - $150,000 per year", "top_companies": ["NASA", "National Institutes of Health", "Google"], "hiring_trends": "The demand for skilled research scientists is on the rise, with a focus on interdisciplinary research, data analysis, and science communication. Recruiters look for candidates with a strong foundation in their field, excellent analytical and communication skills, and the ability to work in teams. Emerging trends include the integration of AI and machine learning into research methodologies, and the increasing importance of translational research.", "future_scope": "This career path is considered a ''High Growth'' area for the next decade, with opportunities expanding not only in traditional research institutions but also in industries such as tech, health, and environmental science. The role of a research scientist is evolving, with a greater emphasis on interdisciplinary collaboration, innovation, and societal impact."}, "reminders": [{"milestone": "Complete foundational courses", "reminder": "Schedule regular study sessions to ensure timely completion of course materials."}, {"milestone": "Start building a professional network", "reminder": "Attend at least one conference or workshop every quarter to expand your professional network."}]}', '[{"milestone": "Complete foundational courses", "reminder": "Schedule regular study sessions to ensure timely completion of course materials."}, {"milestone": "Start building a professional network", "reminder": "Attend at least one conference or workshop every quarter to expand your professional network."}]', '2026-04-08 06:42:59.961904+00'),
	(21, 50, 'Hobby-based Recommendation: Science Writer', '{"steps": [{"step": 1, "action": "Spark Your Curiosity", "description": "As an Adaptive Explorer, it''s essential to spark your curiosity and lay the foundation for a career in science writing. This step matters because it helps you develop a growth mindset, explore various scientific fields, and discover your interests. By doing so, you''ll be better equipped to tackle complex topics and communicate them effectively to your audience.", "skills": ["Basic research skills", "Critical thinking", "Scientific literacy"], "courses": [{"name": "Introduction to Science Writing", "url": "https://www.coursera.org/specializations/science-writing"}, {"name": "The Craft of Science Writing", "url": "https://www.youtube.com/watch?v=3A6F9IeQ8Jg"}], "project": {"name": "Science Scoop", "description": "Write a series of short articles on emerging scientific topics, exploring their implications and potential applications.", "tools": ["Google Scholar", "Science News Websites"], "parameters": ["Clarity of explanation", "Accuracy of information", "Engaging storytelling"]}, "detailed_task": "Read and analyze 5 scientific articles, then write a 500-word blog post summarizing the key findings and their significance.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Build Your Foundation", "description": "As an Ambivert, you''ll benefit from creating a structured environment to learn and grow. This step is crucial because it helps you develop a solid understanding of scientific principles, research methods, and writing techniques. By building a strong foundation, you''ll be able to tackle more complex topics and communicate them effectively to your audience.", "skills": ["Scientific terminology", "Research methodology", "Writing for different audiences"], "courses": [{"name": "Science Writing 101", "url": "https://www.udemy.com/course/science-writing-101/"}, {"name": "The Science of Science Writing", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}], "project": {"name": "Science Primer", "description": "Create a comprehensive guide to a specific scientific field, including key concepts, notable researchers, and recent breakthroughs.", "tools": ["Wikipedia", "Science textbooks"], "parameters": ["Comprehensiveness of coverage", "Accuracy of information", "Readability"]}, "detailed_task": "Create a list of 10 scientific terms and their definitions, then write a 1000-word essay exploring their applications and implications.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Explore Your Niche", "description": "Now that you have a solid foundation, it''s time to explore your niche and develop specialized knowledge. This step is essential because it helps you identify areas of interest, develop a unique voice, and create content that resonates with your target audience. By exploring your niche, you''ll be able to differentiate yourself from others and establish your authority in the field.", "skills": ["Specialized research skills", "Interviewing techniques", "Content creation"], "courses": [{"name": "Science Communication", "url": "https://www.coursera.org/specializations/science-communication"}, {"name": "The Art of Science Storytelling", "url": "https://www.youtube.com/watch?v=Q5yTNyRQ0Yg"}], "project": {"name": "Science Spotlight", "description": "Conduct an in-depth interview with a scientist or researcher, then write a feature article highlighting their work and its significance.", "tools": ["Recording software", "Transcription tools"], "parameters": ["Depth of insight", "Engaging storytelling", "Accuracy of information"]}, "detailed_task": "Reach out to 5 scientists or researchers in your desired niche and request an interview, then write a 1500-word article based on the conversation.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Develop Your Craft", "description": "As you continue to explore your niche, it''s essential to develop your craft and refine your writing skills. This step matters because it helps you create high-quality content, engage your audience, and establish your authority in the field. By developing your craft, you''ll be able to communicate complex scientific concepts in a clear, concise, and compelling manner.", "skills": ["Advanced writing techniques", "Editing and revising", "Visual storytelling"], "courses": [{"name": "Advanced Science Writing", "url": "https://www.udemy.com/course/advanced-science-writing/"}, {"name": "The Science of Visual Storytelling", "url": "https://www.youtube.com/watch?v=jNQXAC9IVRw"}], "project": {"name": "Science Series", "description": "Create a series of in-depth articles on a specific scientific topic, using engaging storytelling and visual elements to convey complex information.", "tools": ["Graphic design software", "Data visualization tools"], "parameters": ["Clarity of explanation", "Engaging storytelling", "Visual appeal"]}, "detailed_task": "Write a 2000-word article on a complex scientific topic, incorporating visual elements and storytelling techniques to make the content more engaging and accessible.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Refine", "description": "As you approach the final stages of your journey, it''s essential to specialize and refine your skills. This step matters because it helps you develop a unique expertise, create high-quality content, and establish yourself as a thought leader in the field. By specializing and refining your skills, you''ll be able to differentiate yourself from others and achieve your career goals.", "skills": ["Expert-level research skills", "Advanced interviewing techniques", "High-level editing and revising"], "courses": [{"name": "Expert Science Writing", "url": "https://www.coursera.org/specializations/expert-science-writing"}, {"name": "The Art of High-Level Science Storytelling", "url": "https://www.youtube.com/watch?v=Km4aX6ZKmVg"}], "project": {"name": "Science Masterpiece", "description": "Create a comprehensive, in-depth article or book on a specific scientific topic, incorporating expert interviews, advanced research, and high-level editing and revising techniques.", "tools": ["Academic databases", "Expert networking platforms"], "parameters": ["Depth of insight", "Accuracy of information", "Engaging storytelling"]}, "detailed_task": "Conduct a thorough literature review on a specific scientific topic, then write a 5000-word article or book chapter that showcases your expertise and establishes your authority in the field.", "timeline": "Months 13-18", "completed": false}, {"step": 6, "action": "Launch Your Career", "description": "As you complete your journey, it''s time to launch your career as a science writer. This step is crucial because it helps you establish yourself as a professional, create a portfolio of high-quality work, and connect with potential employers or clients. By launching your career, you''ll be able to achieve your goals and make a meaningful impact in the field.", "skills": ["Professional networking", "Portfolio development", "Job search strategies"], "courses": [{"name": "Career Development for Science Writers", "url": "https://www.coursera.org/specializations/career-development-science-writers"}, {"name": "The Business of Science Writing", "url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}], "project": {"name": "Science Writer Portfolio", "description": "Create a professional portfolio showcasing your best work, including articles, blog posts, and other writing samples that demonstrate your expertise and style.", "tools": ["Website builders", "Portfolio platforms"], "parameters": ["Quality of writing", "Depth of expertise", "Visual appeal"]}, "detailed_task": "Create a professional website or portfolio, then apply for 5 science writing jobs or freelance opportunities that align with your skills and interests.", "timeline": "Months 19-24", "completed": false}], "internships": ["Science Writing Internship at a prestigious publication", "Research Assistantship at a university or research institution"], "career_outlook": {"salary_range": "Entry-level: $40,000 - $60,000 per year, Senior-level: $80,000 - $120,000 per year", "top_companies": ["The New York Times", "National Geographic", "Scientific American"], "hiring_trends": "The demand for skilled science writers is on the rise, with many publications, universities, and research institutions seeking professionals who can communicate complex scientific concepts to a wide audience. Recruiters look for candidates with a strong portfolio, excellent writing and communication skills, and a deep understanding of scientific principles and research methods.", "future_scope": "The career of a science writer is a safe bet for the next decade, with opportunities for growth and advancement in various fields, including science communication, research, and education. As the world becomes increasingly reliant on scientific advancements, the need for skilled science writers will continue to grow, making this a high-growth career path with a promising future."}, "reminders": [{"milestone": "Complete Step 1", "reminder": "Months 1-3: Focus on building your foundation in science writing"}, {"milestone": "Complete Step 3", "reminder": "Months 7-9: Explore your niche and develop specialized knowledge"}, {"milestone": "Complete Step 6", "reminder": "Months 19-24: Launch your career as a science writer and establish yourself as a professional"}]}', '[{"milestone": "Complete Step 1", "reminder": "Months 1-3: Focus on building your foundation in science writing"}, {"milestone": "Complete Step 3", "reminder": "Months 7-9: Explore your niche and develop specialized knowledge"}, {"milestone": "Complete Step 6", "reminder": "Months 19-24: Launch your career as a science writer and establish yourself as a professional"}]', '2026-04-08 06:44:17.90274+00'),
	(22, 19, 'Software Engineering with a specialization in User Experience (UX) Design', '{"steps": [{"step": 1, "action": "Lay the Foundation", "description": "We start by building a strong foundation in programming principles, understanding the fundamentals of software development, and getting familiar with design thinking. This step matters because it sets the stage for more advanced learning and helps develop a problem-solving mindset. By mastering the basics, you''ll be able to tackle complex projects with confidence.", "skills": ["Programming basics in Python", "Introduction to UX design principles", "Human-computer interaction"], "courses": [{"name": "Python for Everybody", "url": "https://www.coursera.org/specializations/python"}, {"name": "Introduction to User Experience Design", "url": "https://www.udemy.com/course/user-experience-design/"}], "project": {"name": "Personal Portfolio Website", "description": "Create a simple website to showcase your skills and interests using HTML, CSS, and JavaScript.", "tools": ["Visual Studio Code", "GitHub"], "parameters": ["Responsive design", "User-friendly navigation"]}, "detailed_task": "Complete the first 10 exercises on LeetCode to improve your coding skills and create a GitHub repository for your portfolio website.", "timeline": "Months 1-3", "completed": false}, {"step": 2, "action": "Explore and Experiment", "description": "Now that we have a solid foundation, it''s time to explore different areas of software engineering and UX design. This step is crucial because it helps you discover your interests and strengths, and develop a unique perspective on problem-solving. By experimenting with various tools and technologies, you''ll gain hands-on experience and build a strong portfolio.", "skills": ["Front-end development with React", "User research methods", "Wireframing and prototyping"], "courses": [{"name": "React - The Complete Guide", "url": "https://www.udemy.com/course/react-the-complete-guide-incl-redux/"}, {"name": "User Experience (UX) Design Fundamentals", "url": "https://www.coursera.org/specializations/user-experience-design"}], "project": {"name": "To-Do List App", "description": "Design and develop a simple to-do list app using React, focusing on user experience and intuitive design.", "tools": ["React", "Material-UI"], "parameters": ["User authentication", "Data storage and retrieval"]}, "detailed_task": "Conduct user research to identify pain points in existing to-do list apps and create a wireframe prototype of your app using Figma.", "timeline": "Months 4-6", "completed": false}, {"step": 3, "action": "Build Core Skills", "description": "In this phase, we focus on developing core skills in software engineering and UX design. This step is vital because it helps you build a strong technical foundation, learn industry-standard tools, and develop problem-solving strategies. By mastering core skills, you''ll be able to tackle complex projects and collaborate with others effectively.", "skills": ["Back-end development with Node.js", "Database management with MongoDB", "UX writing and content strategy"], "courses": [{"name": "Node.js - The Complete Guide", "url": "https://www.udemy.com/course/nodejs-the-complete-guide/"}, {"name": "UX Writing Fundamentals", "url": "https://www.coursera.org/specializations/ux-writing"}], "project": {"name": "Blog Platform", "description": "Design and develop a blog platform using Node.js, Express, and MongoDB, focusing on user experience, scalability, and performance.", "tools": ["Node.js", "Express", "MongoDB"], "parameters": ["User registration and login", "Article creation and editing"]}, "detailed_task": "Design a database schema for the blog platform using MongoDB and implement user authentication using Passport.js.", "timeline": "Months 7-9", "completed": false}, {"step": 4, "action": "Network and Collaborate", "description": "Now that we have a strong technical foundation, it''s time to network with other professionals, collaborate on projects, and participate in design communities. This step is essential because it helps you build relationships, learn from others, and stay updated on industry trends. By networking and collaborating, you''ll gain access to new opportunities, feedback, and mentorship.", "skills": ["Agile development methodologies", "Version control with Git", "Design systems and design languages"], "courses": [{"name": "Agile Development with Scrum", "url": "https://www.coursera.org/specializations/agile-development"}, {"name": "Design Systems with Figma", "url": "https://www.udemy.com/course/design-systems-with-figma/"}], "project": {"name": "Open-Source Contribution", "description": "Contribute to an open-source project on GitHub, focusing on UX design, front-end development, or back-end development.", "tools": ["GitHub", "Figma"], "parameters": ["Code review and feedback", "Collaboration with other contributors"]}, "detailed_task": "Join a design community on Discord or Slack and participate in discussions on design systems, sharing your knowledge and learning from others.", "timeline": "Months 10-12", "completed": false}, {"step": 5, "action": "Specialize and Refine", "description": "In this phase, we focus on specializing in UX design, refining our skills, and developing a unique value proposition. This step is critical because it helps you stand out in a competitive job market, develop a personal brand, and create a professional portfolio. By specializing and refining your skills, you''ll be able to tackle complex design challenges and create innovative solutions.", "skills": ["UX research and analysis", "Interaction design and prototyping", "Designing for accessibility"], "courses": [{"name": "UX Research and Analysis", "url": "https://www.coursera.org/specializations/ux-research"}, {"name": "Interaction Design with Figma", "url": "https://www.udemy.com/course/interaction-design-with-figma/"}], "project": {"name": "Personal Project Showcase", "description": "Create a professional portfolio website showcasing your UX design projects, skills, and experience.", "tools": ["Figma", "Adobe XD"], "parameters": ["Case studies and project descriptions", "Visual design and branding"]}, "detailed_task": "Conduct a UX audit of a popular website or app, identifying areas for improvement and creating a redesign concept using Figma.", "timeline": "Months 13-15", "completed": false}, {"step": 6, "action": "Launch and Grow", "description": "In the final phase, we focus on launching your career, growing your professional network, and continuously learning and improving. This step is vital because it helps you stay up-to-date with industry trends, develop a growth mindset, and create a long-term career strategy. By launching and growing your career, you''ll be able to achieve your goals, make a meaningful impact, and create a lasting legacy.", "skills": ["Career development and job search strategies", "Personal branding and online presence", "Industry trends and emerging technologies"], "courses": [{"name": "Career Development and Job Search Strategies", "url": "https://www.coursera.org/specializations/career-development"}, {"name": "Personal Branding and Online Presence", "url": "https://www.udemy.com/course/personal-branding-and-online-presence/"}], "project": {"name": "Professional Networking and Job Search", "description": "Create a professional online presence, network with industry professionals, and apply for job openings in software engineering and UX design.", "tools": ["LinkedIn", "Glassdoor"], "parameters": ["Resume and cover letter optimization", "Interview preparation and practice"]}, "detailed_task": "Attend a design conference or meetups, networking with professionals and learning about industry trends and best practices.", "timeline": "Months 16-18", "completed": false}], "internships": ["UX Design Intern at Google", "Software Engineering Intern at Microsoft"], "career_outlook": {"salary_range": "INR 8-20 lakhs per annum (entry-level to senior roles)", "top_companies": ["Google", "Microsoft", "Amazon"], "hiring_trends": "The demand for software engineers with UX design skills is increasing rapidly, with companies looking for professionals who can create user-centered and intuitive products. Recruiters look for candidates with a strong portfolio, excellent problem-solving skills, and the ability to collaborate with cross-functional teams. The current hiring trends focus on emerging technologies like AI, AR, and VR, and companies are looking for professionals who can design and develop innovative solutions using these technologies.", "future_scope": "Software engineering with a specialization in UX design is a high-growth career path, with a wide range of job opportunities and a high potential for career advancement. With the increasing demand for digital products and services, the role of software engineers and UX designers will continue to evolve, and professionals with these skills will be in high demand. This career path offers a safe bet for the next decade, with opportunities for growth, learning, and innovation."}, "reminders": [{"milestone": "Complete the first 10 exercises on LeetCode", "reminder": "Month 2"}, {"milestone": "Join a design community on Discord or Slack", "reminder": "Month 10"}]}', '[{"milestone": "Complete the first 10 exercises on LeetCode", "reminder": "Month 2"}, {"milestone": "Join a design community on Discord or Slack", "reminder": "Month 10"}]', '2026-04-22 16:47:44.513249+00');


