INSERT INTO "public"."college_recommendations" ("id", "user_id", "career_title", "college_data", "created_at") VALUES
	(1, 7, 'Industrial Engineering and Operations Research', '{"colleges": [{"name": "Indian Institute of Technology (IIT) Delhi", "location": "New Delhi, India", "ranking": "Top 3 in India", "admission_criteria": "Admission to IIT Delhi is based on JEE Advanced exam scores, with a typical cutoff of 2000-3000 for Industrial Engineering. Eligible candidates must have passed 10+2 with a minimum of 75% marks. The application process usually starts in May and ends in June.", "courses_offered": ["B.Tech Industrial Engineering", "M.Tech Industrial Engineering and Management", "M.S. Research in Industrial Engineering"], "placement_rate": "95%", "avg_package": "15-20 lakhs INR", "top_recruiters": ["Tata Motors", "Siemens", "L&T"], "highlights": "IIT Delhi has an excellent reputation for its Industrial Engineering program, with a strong focus on research and industry partnerships. The institute has a well-equipped manufacturing laboratory and a dedicated center for industrial engineering and management. The faculty is composed of renowned experts in the field.", "website": "https://www.iitd.ac.in/"}, {"name": "Georgia Institute of Technology", "location": "Atlanta, USA", "ranking": "#12 Globally", "admission_criteria": "Admission to Georgia Tech requires a minimum SAT score of 1300 or ACT score of 28, along with a high school GPA of 3.5 or higher. International students must also submit TOEFL or IELTS scores. The application deadline is usually in January for fall semester.", "courses_offered": ["B.S. Industrial Engineering", "M.S. Industrial Engineering", "Ph.D. in Industrial Engineering"], "placement_rate": "Near 100%", "avg_package": "80,000-100,000 USD", "top_recruiters": ["Accenture", "IBM", "Procter & Gamble"], "highlights": "Georgia Tech has a highly-regarded Industrial Engineering program, with a strong focus on analytics, optimization, and systems engineering. The institute has a dedicated Career Services office and a large network of alumni in top companies.", "website": "https://www.gatech.edu/"}, {"name": "National Institute of Technology (NIT) Tiruchirappalli", "location": "Tiruchirappalli, India", "ranking": "Top 10 in India", "admission_criteria": "Admission to NIT Tiruchirappalli is based on JEE Main exam scores, with a typical cutoff of 10,000-15,000 for Industrial Engineering. Eligible candidates must have passed 10+2 with a minimum of 75% marks. The application process usually starts in June and ends in July.", "courses_offered": ["B.Tech Industrial Engineering", "M.Tech Industrial Safety Engineering", "M.Sc. in Industrial Engineering"], "placement_rate": "90%", "avg_package": "8-12 lakhs INR", "top_recruiters": ["Ashok Leyland", "BHEL", "Cement Corporation of India"], "highlights": "NIT Tiruchirappalli has a well-established Industrial Engineering program, with a strong focus on practical training and industry partnerships. The institute has a dedicated Center for Industrial Engineering and Management, and the faculty is composed of experienced professionals.", "website": "https://www.nitt.edu/"}, {"name": "University of Michigan", "location": "Ann Arbor, USA", "ranking": "#23 Globally", "admission_criteria": "Admission to the University of Michigan requires a minimum SAT score of 1300 or ACT score of 28, along with a high school GPA of 3.5 or higher. International students must also submit TOEFL or IELTS scores. The application deadline is usually in November for winter semester.", "courses_offered": ["B.S.E. Industrial and Operations Engineering", "M.S.E. Industrial and Operations Engineering", "Ph.D. in Industrial and Operations Engineering"], "placement_rate": "95%", "avg_package": "70,000-100,000 USD", "top_recruiters": ["Ford Motor Company", "General Motors", "3M"], "highlights": "The University of Michigan has a highly-regarded Industrial and Operations Engineering program, with a strong focus on analytics, optimization, and systems engineering. The institute has a dedicated Career Center and a large network of alumni in top companies.", "website": "https://www.umich.edu/"}, {"name": "Indian Institute of Technology (IIT) Kanpur", "location": "Kanpur, India", "ranking": "Top 5 in India", "admission_criteria": "Admission to IIT Kanpur is based on JEE Advanced exam scores, with a typical cutoff of 2000-3000 for Industrial Engineering. Eligible candidates must have passed 10+2 with a minimum of 75% marks. The application process usually starts in May and ends in June.", "courses_offered": ["B.Tech Industrial and Management Engineering", "M.Tech Industrial and Management Engineering", "M.S. Research in Industrial Engineering"], "placement_rate": "95%", "avg_package": "15-20 lakhs INR", "top_recruiters": ["Hindustan Unilever", "Larsen & Toubro", "Tata Consultancy Services"], "highlights": "IIT Kanpur has an excellent reputation for its Industrial and Management Engineering program, with a strong focus on research and industry partnerships. The institute has a well-equipped manufacturing laboratory and a dedicated center for industrial engineering and management.", "website": "https://www.iitk.ac.in/"}], "preparation_tips": ["Focus on developing a strong foundation in mathematics, physics, and chemistry, as these are essential subjects for Industrial Engineering.", "Prepare for JEE Advanced or other entrance exams by practicing mock tests, and solving previous year questions.", "Develop skills in programming languages like Python, C++, and MATLAB, as these are widely used in Industrial Engineering.", "Gain practical experience through internships, volunteer work, or projects, to demonstrate your skills and passion for Industrial Engineering to college admissions committees."]}', '2026-03-13 19:07:06+00'),
	(2, 15, 'Hobby-based Recommendation: Game Developer', '{"colleges": [{"name": "Indian Institute of Technology (IIT) Kanpur", "location": "Kanpur, India", "ranking": "Top 3 in India", "admission_criteria": "Admission to IIT Kanpur is based on JEE Advanced exams, with a cut-off of 10+2 with PCM, and a minimum of 75% marks. The application process typically starts in April, with key dates including the JEE Main exam in February and the JEE Advanced exam in May. Eligibility criteria also include a minimum age of 18 years and a maximum age of 25 years.", "courses_offered": ["B.Tech Computer Science and Engineering", "M.Tech Computer Science and Engineering", "M.Sc Computer Science"], "placement_rate": "95%", "avg_package": "15-20 Lakhs INR", "top_recruiters": ["Google", "Microsoft", "Amazon"], "highlights": "IIT Kanpur is a premier institute for computer science and engineering, with a strong focus on research and development. The institute has a dedicated gaming and animation lab, providing students with hands-on experience in game development. The faculty at IIT Kanpur includes renowned experts in the field of computer science, providing students with excellent guidance and mentorship.", "website": "https://www.iitk.ac.in/"}, {"name": "University of California, Los Angeles (UCLA)", "location": "Los Angeles, USA", "ranking": "#12 Globally", "admission_criteria": "Admission to UCLA is based on SAT or ACT exams, with a minimum GPA of 3.0. The application process typically starts in November, with key dates including the SAT or ACT exam in December and the application deadline in January. Eligibility criteria also include a minimum of 2 years of high school coursework in math and science.", "courses_offered": ["B.S Computer Science", "B.A Computer Science", "M.S Computer Science"], "placement_rate": "Near 100%", "avg_package": "$80,000-$120,000 USD", "top_recruiters": ["Facebook", "Apple", "Google"], "highlights": "UCLA is a world-renowned university, with a strong computer science program that includes courses in game development, artificial intelligence, and data science. The university has a dedicated game lab, providing students with hands-on experience in game development and a chance to work with industry professionals. The faculty at UCLA includes renowned experts in the field of computer science, providing students with excellent guidance and mentorship.", "website": "https://www.ucla.edu/"}, {"name": "National Institute of Technology (NIT) Rourkela", "location": "Rourkela, India", "ranking": "Top 10 in India", "admission_criteria": "Admission to NIT Rourkela is based on JEE Main exams, with a cut-off of 10+2 with PCM, and a minimum of 75% marks. The application process typically starts in April, with key dates including the JEE Main exam in February and the JEE Main result in June. Eligibility criteria also include a minimum age of 18 years and a maximum age of 25 years.", "courses_offered": ["B.Tech Computer Science and Engineering", "M.Tech Computer Science and Engineering", "M.Sc Computer Science"], "placement_rate": "90%", "avg_package": "8-12 Lakhs INR", "top_recruiters": ["Microsoft", "Amazon", "TCS"], "highlights": "NIT Rourkela is a premier institute for computer science and engineering, with a strong focus on research and development. The institute has a dedicated gaming and animation lab, providing students with hands-on experience in game development. The faculty at NIT Rourkela includes renowned experts in the field of computer science, providing students with excellent guidance and mentorship.", "website": "https://www.nitrkl.ac.in/"}, {"name": "Carnegie Mellon University", "location": "Pittsburgh, USA", "ranking": "#1 in Computer Science Globally", "admission_criteria": "Admission to Carnegie Mellon University is based on SAT or ACT exams, with a minimum GPA of 3.5. The application process typically starts in November, with key dates including the SAT or ACT exam in December and the application deadline in January. Eligibility criteria also include a minimum of 2 years of high school coursework in math and science.", "courses_offered": ["B.S Computer Science", "B.A Computer Science", "M.S Computer Science"], "placement_rate": "Near 100%", "avg_package": "$100,000-$150,000 USD", "top_recruiters": ["Google", "Facebook", "Microsoft"], "highlights": "Carnegie Mellon University is a world-renowned university, with a top-ranked computer science program that includes courses in game development, artificial intelligence, and data science. The university has a dedicated game lab, providing students with hands-on experience in game development and a chance to work with industry professionals. The faculty at Carnegie Mellon includes renowned experts in the field of computer science, providing students with excellent guidance and mentorship.", "website": "https://www.cmu.edu/"}, {"name": "Indian Institute of Information Technology (IIIT) Hyderabad", "location": "Hyderabad, India", "ranking": "Top 5 in India", "admission_criteria": "Admission to IIIT Hyderabad is based on JEE Main exams, with a cut-off of 10+2 with PCM, and a minimum of 75% marks. The application process typically starts in April, with key dates including the JEE Main exam in February and the JEE Main result in June. Eligibility criteria also include a minimum age of 18 years and a maximum age of 25 years.", "courses_offered": ["B.Tech Computer Science and Engineering", "M.Tech Computer Science and Engineering", "M.Sc Computer Science"], "placement_rate": "95%", "avg_package": "12-18 Lakhs INR", "top_recruiters": ["Google", "Amazon", "Microsoft"], "highlights": "IIIT Hyderabad is a premier institute for computer science and engineering, with a strong focus on research and development. The institute has a dedicated gaming and animation lab, providing students with hands-on experience in game development. The faculty at IIIT Hyderabad includes renowned experts in the field of computer science, providing students with excellent guidance and mentorship.", "website": "https://www.iiith.ac.in/"}], "preparation_tips": ["Focus on building a strong foundation in math and science, particularly in areas like linear algebra, calculus, and programming.", "Develop skills in programming languages like C, C++, Java, and Python, and familiarize yourself with game development frameworks like Unity and Unreal Engine.", "Participate in game development competitions and hackathons to gain practical experience and build a portfolio of your work.", "Stay up-to-date with industry trends and developments, and network with professionals in the field to learn more about the game development industry and stay ahead of the curve."]}', '2026-03-13 19:27:01+00'),
	(3, 7, 'Industrial Engineering and Operations Research', '{"colleges": [{"name": "National Institute of Technology, Tiruchirappalli", "location": "Tiruchirappalli, India", "ranking": "Top 10 in India", "admission_criteria": "Admission to NIT Trichy is based on JEE Main scores, with a typical cutoff range of 500-2000 for Industrial Engineering. Key dates include JEE Main exam in April and JoSAA counseling in June-July. Eligibility requires 75% in 12th board exams from a recognized board.", "courses_offered": ["B.Tech Industrial Engineering", "M.Tech Industrial Engineering", "M.Tech Operations Research", "Ph.D. in Industrial Engineering"], "placement_rate": "95%", "avg_package": "8-12 LPA", "top_recruiters": ["Tata Motors", "General Motors", "Hyundai", "Honda"], "highlights": "NIT Trichy has a strong reputation for industrial engineering and operations research, with a dedicated department and excellent faculty. The institute has a strong industry connection and offers various internship and project opportunities. The campus is well-equipped with modern facilities and infrastructure.", "website": "https://www.nitt.edu/"}, {"name": "Indian Institute of Technology, Kharagpur", "location": "Kharagpur, India", "ranking": "Top 5 in India", "admission_criteria": "Admission to IIT Kharagpur is based on JEE Advanced scores, with a typical cutoff range of 200-1000 for Industrial Engineering. Key dates include JEE Advanced exam in May and JoSAA counseling in June-July. Eligibility requires 75% in 12th board exams from a recognized board.", "courses_offered": ["B.Tech Industrial Engineering", "M.Tech Industrial Engineering and Management", "M.Tech Operations Research", "Ph.D. in Industrial Engineering"], "placement_rate": "Near 100%", "avg_package": "10-18 LPA", "top_recruiters": ["Google", "Microsoft", "Amazon", "Tata Consultancy Services"], "highlights": "IIT Kharagpur is one of the top institutes in India, with a strong focus on research and innovation. The industrial engineering department has a strong reputation and excellent faculty, with a wide range of research areas and projects. The campus is well-equipped with modern facilities and infrastructure.", "website": "https://www.iitkgp.ac.in/"}, {"name": "Georgia Institute of Technology", "location": "Atlanta, USA", "ranking": "#26 Globally", "admission_criteria": "Admission to Georgia Tech requires SAT scores (1300-1500), ACT scores (28-34), and a GPA of 3.8 or higher. Key dates include application deadlines in November and January. Eligibility requires a high school diploma or equivalent.", "courses_offered": ["B.S. in Industrial Engineering", "M.S. in Industrial Engineering", "M.S. in Operations Research", "Ph.D. in Industrial Engineering"], "placement_rate": "95%", "avg_package": "$80,000 - $120,000", "top_recruiters": ["Amazon", "Microsoft", "IBM", "Coca-Cola"], "highlights": "Georgia Tech is a top-ranked university globally, with a strong reputation for industrial engineering and operations research. The Stewart School of Industrial and Systems Engineering has a dedicated faculty and excellent research areas, with a wide range of internship and project opportunities.", "website": "https://www.gatech.edu/"}, {"name": "University of California, Berkeley", "location": "Berkeley, USA", "ranking": "#27 Globally", "admission_criteria": "Admission to UC Berkeley requires SAT scores (1300-1500), ACT scores (28-34), and a GPA of 3.8 or higher. Key dates include application deadlines in November and January. Eligibility requires a high school diploma or equivalent.", "courses_offered": ["B.S. in Industrial Engineering and Operations Research", "M.S. in Industrial Engineering and Operations Research", "M.Eng. in Industrial Engineering and Operations Research", "Ph.D. in Industrial Engineering and Operations Research"], "placement_rate": "95%", "avg_package": "$90,000 - $140,000", "top_recruiters": ["Google", "Apple", "Amazon", "Microsoft"], "highlights": "UC Berkeley is a top-ranked university globally, with a strong reputation for industrial engineering and operations research. The department has a dedicated faculty and excellent research areas, with a wide range of internship and project opportunities.", "website": "https://www.berkeley.edu/"}, {"name": "Indian Institute of Technology, Delhi", "location": "New Delhi, India", "ranking": "Top 3 in India", "admission_criteria": "Admission to IIT Delhi is based on JEE Advanced scores, with a typical cutoff range of 200-1000 for Industrial Engineering. Key dates include JEE Advanced exam in May and JoSAA counseling in June-July. Eligibility requires 75% in 12th board exams from a recognized board.", "courses_offered": ["B.Tech Industrial Engineering", "M.Tech Industrial Engineering and Management", "M.Tech Operations Research", "Ph.D. in Industrial Engineering"], "placement_rate": "Near 100%", "avg_package": "12-20 LPA", "top_recruiters": ["Tata Motors", "General Motors", "Hyundai", "Honda"], "highlights": "IIT Delhi is one of the top institutes in India, with a strong focus on research and innovation. The industrial engineering department has a strong reputation and excellent faculty, with a wide range of research areas and projects. The campus is well-equipped with modern facilities and infrastructure.", "website": "https://www.iitd.ac.in/"}], "preparation_tips": ["Focus on building a strong foundation in mathematics and physics, particularly in areas like calculus, linear algebra, and probability.", "Develop problem-solving skills and logical reasoning, which are crucial for industrial engineering and operations research.", "Practice and prepare for entrance exams like JEE Main and Advanced, SAT, and ACT, depending on the colleges you''re targeting.", "Build a strong portfolio and participate in internships, projects, and research activities to demonstrate your skills and interest in the field."]}', '2026-03-22 19:42:14+00'),
	(4, 17, 'Social Entrepreneur', '{"colleges": [{"name": "Indian Institute of Technology Delhi", "location": "New Delhi, India", "ranking": "Top 3 in India", "admission_criteria": "Admission is based on JEE Advanced scores, with cutoffs varying by department. Eligibility requires a minimum of 75% in 12th standard. Key dates include May for JEE Advanced and June for counseling. Eligibility also includes a minimum age of 25 for some courses.", "courses_offered": ["B.Tech Computer Science", "M.Tech Environmental Science", "M.Sc Development Studies"], "placement_rate": "95%", "avg_package": "15 lakhs INR", "top_recruiters": ["Google", "Microsoft", "Tata Consultancy Services"], "highlights": "IIT Delhi offers a strong foundation in technology and sciences, with opportunities for social entrepreneurship through its various research centers and incubation cells. The institute has a strong network of alumni and industry connections, providing ample opportunities for social impact. Its location in the national capital also provides access to policy makers and government institutions.", "website": "https://www.iitd.ac.in/"}, {"name": "University of California, Berkeley", "location": "Berkeley, USA", "ranking": "#12 Globally", "admission_criteria": "Admission requires SAT or ACT scores, with a minimum GPA of 3.0. International students also require TOEFL or IELTS scores. The deadline for application is typically in November for the fall semester. Eligibility also includes completion of a minimum of 12 years of schooling.", "courses_offered": ["B.A. Environmental Economics", "M.P.P. Public Policy", "M.B.A. Social Impact"], "placement_rate": "Near 100%", "avg_package": "80,000 USD", "top_recruiters": ["Facebook", "Apple", "World Bank"], "highlights": "UC Berkeley offers a wide range of courses and research opportunities in social entrepreneurship, with a strong focus on environmental sustainability and social justice. The university has a diverse and vibrant community, with numerous student organizations and clubs focused on social impact. Its location in the San Francisco Bay Area also provides access to a thriving startup ecosystem and network of social entrepreneurs.", "website": "https://www.berkeley.edu/"}, {"name": "Azim Premji University", "location": "Bengaluru, India", "ranking": "Top 10 in India for Social Impact", "admission_criteria": "Admission is based on a national entrance test, with a minimum eligibility of 50% in 12th standard. The deadline for application is typically in March. Eligibility also includes a minimum age of 20 for some courses.", "courses_offered": ["B.A. Development Studies", "M.A. Public Policy", "M.A. Development"], "placement_rate": "90%", "avg_package": "6 lakhs INR", "top_recruiters": ["Azim Premji Foundation", "Oxfam India", "UNICEF"], "highlights": "Azim Premji University offers a unique focus on social impact and development, with a strong emphasis on fieldwork and practical experience. The university has a strong network of partnerships with NGOs and social organizations, providing opportunities for internships and placements. Its location in Bengaluru also provides access to a thriving startup ecosystem and network of social entrepreneurs.", "website": "https://www.azimpremjiuniversity.edu.in/"}, {"name": "London School of Economics and Political Science", "location": "London, UK", "ranking": "#5 Globally", "admission_criteria": "Admission requires A-level scores, with a minimum GPA of 3.5. International students also require IELTS or TOEFL scores. The deadline for application is typically in January for the fall semester. Eligibility also includes completion of a minimum of 12 years of schooling.", "courses_offered": ["B.Sc International Social and Public Policy", "M.Sc Development Studies", "M.Sc Environmental Policy"], "placement_rate": "95%", "avg_package": "45,000 GBP", "top_recruiters": ["World Bank", "UNICEF", "UK Government"], "highlights": "LSE offers a world-class education in social sciences, with a strong focus on international development and social policy. The university has a diverse and international community, with numerous student organizations and clubs focused on social impact. Its location in London also provides access to a global network of policymakers, NGOs, and social organizations.", "website": "https://www.lse.ac.uk/"}, {"name": "Tata Institute of Social Sciences", "location": "Mumbai, India", "ranking": "Top 5 in India for Social Work", "admission_criteria": "Admission is based on a national entrance test, with a minimum eligibility of 50% in 12th standard. The deadline for application is typically in March. Eligibility also includes a minimum age of 20 for some courses.", "courses_offered": ["B.A. Social Work", "M.A. Social Work", "M.A. Development Studies"], "placement_rate": "90%", "avg_package": "5 lakhs INR", "top_recruiters": ["Tata Group", "Oxfam India", "Save the Children"], "highlights": "TISS offers a strong focus on social work and development, with a strong emphasis on fieldwork and practical experience. The institute has a strong network of partnerships with NGOs and social organizations, providing opportunities for internships and placements. Its location in Mumbai also provides access to a thriving social impact ecosystem and network of social entrepreneurs.", "website": "https://www.tiss.edu/"}], "preparation_tips": ["Develop a strong foundation in social sciences and humanities, with a focus on development studies, economics, and policy.", "Gain practical experience through internships, volunteer work, or social projects, to build a strong portfolio of social impact.", "Build a strong network of professionals and organizations in the field of social entrepreneurship, through attending conferences, workshops, and online forums.", "Develop a strong understanding of the social issues and challenges facing the world, and be prepared to articulate your own vision for social impact and change."]}', '2026-03-26 12:49:32.385951+00'),
	(5, 7, 'Architecture and Urban Systems', '{"colleges": [{"name": "Indian Institute of Technology (IIT) Kharagpur", "location": "Kharagpur, India", "ranking": "Top 3 in India", "admission_criteria": "Admission is based on JEE Advanced scores, with a minimum cutoff of 2000 for the Architecture program. Eligible candidates must have passed 10+2 with a minimum of 75% marks in Physics, Chemistry, and Mathematics. The application process typically begins in February, and the entrance exam is held in May.", "courses_offered": ["B.Arch", "M.Arch", "B.Tech in Civil Engineering", "M.Tech in Urban Planning"], "placement_rate": "95%", "avg_package": "8-12 LPA", "top_recruiters": ["L&T", "Tata Consulting Engineers", "AECOM"], "highlights": "IIT Kharagpur is known for its rigorous academic programs and research opportunities in architecture and urban systems. The institute has a strong industry connection, with many top companies recruiting from the campus. The faculty is highly experienced and includes renowned architects and urban planners.", "website": "https://www.iitkgp.ac.in/"}, {"name": "Massachusetts Institute of Technology (MIT)", "location": "Cambridge, USA", "ranking": "#1 Globally", "admission_criteria": "Admission is based on SAT or ACT scores, with a minimum score of 1500 or 34 respectively. Eligible candidates must have passed 10+2 with a minimum GPA of 3.5. The application process typically begins in September, and the deadline is in December.", "courses_offered": ["Bachelor of Science in Architecture", "Master of Architecture", "Master of Science in Urban Studies and Planning"], "placement_rate": "Near 100%", "avg_package": "$80,000 - $120,000", "top_recruiters": ["Skidmore, Owings & Merrill", "Gensler", "HOK"], "highlights": "MIT is a world-renowned institution for architecture and urban systems, with a strong focus on innovation and research. The faculty includes some of the most influential architects and urban planners in the world. The institute has a strong industry connection, with many top companies recruiting from the campus.", "website": "https://www.mit.edu/"}, {"name": "School of Planning and Architecture (SPA) Delhi", "location": "New Delhi, India", "ranking": "Top 2 in India", "admission_criteria": "Admission is based on JEE Main and JEE Advanced scores, with a minimum cutoff of 1800 for the Architecture program. Eligible candidates must have passed 10+2 with a minimum of 50% marks in Physics, Chemistry, and Mathematics. The application process typically begins in February, and the entrance exam is held in May.", "courses_offered": ["B.Arch", "M.Arch", "B.Plan", "M.Plan"], "placement_rate": "90%", "avg_package": "6-10 LPA", "top_recruiters": ["CPWD", "NBCC", "L&T"], "highlights": "SPA Delhi is one of the oldest and most prestigious institutions for architecture and urban planning in India. The institute has a strong focus on research and has collaborated with many top international universities. The faculty is highly experienced and includes renowned architects and urban planners.", "website": "https://www.spa.ac.in/"}, {"name": "University of California, Berkeley", "location": "Berkeley, USA", "ranking": "#2 Globally", "admission_criteria": "Admission is based on SAT or ACT scores, with a minimum score of 1400 or 31 respectively. Eligible candidates must have passed 10+2 with a minimum GPA of 3.5. The application process typically begins in September, and the deadline is in November.", "courses_offered": ["Bachelor of Arts in Architecture", "Master of Architecture", "Master of Urban Design"], "placement_rate": "Near 100%", "avg_package": "$70,000 - $110,000", "top_recruiters": ["Gensler", "HOK", "Skidmore, Owings & Merrill"], "highlights": "UC Berkeley is a world-renowned institution for architecture and urban systems, with a strong focus on innovation and research. The faculty includes some of the most influential architects and urban planners in the world. The institute has a strong industry connection, with many top companies recruiting from the campus.", "website": "https://www.berkeley.edu/"}, {"name": "National Institute of Technology (NIT) Calicut", "location": "Kozhikode, India", "ranking": "Top 10 in India", "admission_criteria": "Admission is based on JEE Main scores, with a minimum cutoff of 1500 for the Architecture program. Eligible candidates must have passed 10+2 with a minimum of 50% marks in Physics, Chemistry, and Mathematics. The application process typically begins in February, and the entrance exam is held in May.", "courses_offered": ["B.Arch", "M.Arch", "B.Tech in Civil Engineering", "M.Tech in Urban Planning"], "placement_rate": "85%", "avg_package": "5-8 LPA", "top_recruiters": ["L&T", "Tata Consulting Engineers", "AECOM"], "highlights": "NIT Calicut is a premier institution for architecture and urban planning in India, with a strong focus on research and innovation. The faculty is highly experienced and includes renowned architects and urban planners. The institute has a strong industry connection, with many top companies recruiting from the campus.", "website": "https://www.nitc.ac.in/"}], "preparation_tips": ["Focus on developing a strong foundation in mathematics and physics, as these subjects are crucial for architecture and urban systems.", "Prepare for entrance exams like JEE Main and JEE Advanced, and aim to score high to increase the chances of getting into top institutions.", "Participate in architecture and design competitions to develop your skills and build a portfolio that showcases your work.", "Gain practical experience by interning with architecture and urban planning firms, or volunteering for projects that align with your interests."]}', '2026-03-27 06:33:14.979683+00'),
	(6, 23, 'Research Scientist', '{"colleges": [{"name": "Indian Institute of Technology Delhi", "location": "New Delhi, India", "ranking": "Top 3 in India", "admission_criteria": "Admission to IIT Delhi is based on JEE Advanced scores, with a cutoff of 10% for general category students. The eligibility criteria include a minimum of 75% aggregate marks in the qualifying exam. Key dates include the JEE Advanced exam in May and the counseling process in June-July. Students must also meet the age eligibility criteria, which is 25 years for general category students.", "courses_offered": ["B.Tech Computer Science", "M.Tech Data Science", "M.Sc Mathematics", "Ph.D. in Computer Science"], "placement_rate": "95%", "avg_package": "15 lakh INR", "top_recruiters": ["Google", "Microsoft", "Amazon"], "highlights": "IIT Delhi is one of the premier institutes in India, known for its strong research focus and state-of-the-art infrastructure. The institute has a strong alumni network and provides excellent opportunities for research collaborations. The campus is also home to several research centers and institutes, providing students with hands-on experience in cutting-edge research.", "website": "https://www.iitd.ac.in/"}, {"name": "Massachusetts Institute of Technology", "location": "Cambridge, USA", "ranking": "#1 Globally", "admission_criteria": "Admission to MIT is based on SAT or ACT scores, with a minimum score of 1500 or 34 respectively. The eligibility criteria include a minimum GPA of 4.13 and completion of high school diploma. Key dates include the application deadline in January and the decision notification in March. Students must also submit letters of recommendation and a personal statement.", "courses_offered": ["Bachelor of Science in Computer Science", "Master of Science in Data Science", "Ph.D. in Computer Science", "Bachelor of Science in Biology"], "placement_rate": "Near 100%", "avg_package": "120,000 USD", "top_recruiters": ["Google", "Microsoft", "Facebook"], 